#!/bin/bash

# n8n-host.sh - N8N Cloud Manager
# Generated by build.sh — DO NOT EDIT DIRECTLY
# Edit source files in src/ then run: bash build.sh

# ---- src/lib/globals.sh ----
# --- Định nghĩa màu sắc ---
RED='\e[38;5;217m'      # hồng nhạt
GREEN='\e[38;5;151m'    # xanh lá nhạt
YELLOW='\e[38;5;229m'   # vàng nhạt
CYAN='\e[38;5;159m'     # xanh dương nhạt
NC='\e[0m'              # reset màu

# --- Biến toàn cục ---
N8N_DIR="/n8n-cloud"                                        # Thư mục cài đặt N8N
ENV_FILE="${N8N_DIR}/.env"                                  # File biến môi trường
DOCKER_COMPOSE_FILE="${N8N_DIR}/docker-compose.yml"         # File Docker Compose
DOCKER_COMPOSE_CMD="docker compose"                         # Lệnh docker compose (sẽ tự cập nhật)
SPINNER_PID=0                                               # PID của tiến trình spinner
N8N_CONTAINER_NAME="n8n_app"                                # Tên container N8N
N8N_SERVICE_NAME="n8n"                                      # Tên service trong docker-compose
NGINX_EXPORT_INCLUDE_DIR="/etc/nginx/n8n_export_includes"   # Thư mục chứa config Nginx tạm
NGINX_EXPORT_INCLUDE_FILE_BASENAME="n8n_export_location"    # Tên file base cho Nginx include
TEMPLATE_DIR="/n8n-templates"                               # Thư mục chứa file template trên host
TEMPLATE_FILE_NAME="import-workflow-credentials.json"       # Tên file template import
INSTALL_PATH="/usr/local/bin/n8n-host"                      # Đường dẫn cài đặt script

# ---- src/lib/utils.sh ----
# --- Hàm Kiểm Tra ---
check_root() {
  if [[ $EUID -ne 0 ]]; then
    echo -e "\n${RED}[!] Lỗi: Bạn cần chạy script với quyền quản trị viên (root).${NC}\n"
    exit 1
  fi
}

command_exists() {
  command -v "$1" >/dev/null 2>&1
}

is_package_installed() {
  # Kiểm tra gói đã cài chưa — hỗ trợ cả Debian/Ubuntu (dpkg) và RHEL/CentOS (rpm)
  if command_exists dpkg; then
    dpkg -s "$1" &> /dev/null
  elif command_exists rpm; then
    rpm -q "$1" &> /dev/null
  else
    # Fallback: kiểm tra qua tên lệnh
    command_exists "$1"
  fi
}

# --- Hàm Phụ Trợ ---
get_public_ip() {
  local ip
  ip=$(curl -s --ipv4 https://ifconfig.co) || \
  ip=$(curl -s --ipv4 https://api.ipify.org) || \
  ip=$(curl -s --ipv4 https://icanhazip.com) || \
  ip=$(hostname -I | awk '{print $1}')
  if [[ -z "$ip" ]]; then
    echo -e "${RED}[!] Không thể lấy địa chỉ IP public của server.${NC}"
    return 1
  fi
  echo "$ip"
  return 0
}

generate_random_string() {
  local length="${1:-32}"
  LC_ALL=C tr -dc 'A-Za-z0-9' < /dev/urandom | head -c "$length"
}

update_env_file() {
  local key="$1"
  local value="$2"
  if [ ! -f "${ENV_FILE}" ]; then
    echo -e "${RED}Lỗi: File ${ENV_FILE} không tồn tại. Không thể cập nhật.${NC}"
    return 1
  fi
  if grep -q "^${key}=" "${ENV_FILE}"; then
    sudo sed -i "s|^${key}=.*|${key}=${value}|" "${ENV_FILE}"
  else
    echo "${key}=${value}" | sudo tee -a "${ENV_FILE}" > /dev/null
  fi
}

# --- Spinner (hiệu ứng loading) ---
_spinner() {
    local spin_chars=('⠋' '⠙' '⠹' '⠸' '⠼' '⠴' '⠦' '⠧' '⠇' '⠏')
    local i=0
    tput civis # ẩn con trỏ
    while true; do
        echo -n -e " ${CYAN}${spin_chars[$i]} $1 ${NC}\r"
        i=$(( (i+1) % ${#spin_chars[@]} ))
        sleep 0.1
    done
}

start_spinner() {
    local message="$1"
    if [[ $SPINNER_PID -ne 0 ]]; then
        stop_spinner
    fi
    _spinner "$message" &
    SPINNER_PID=$!
    trap "stop_spinner;" SIGINT SIGTERM
}

stop_spinner() {
    if [[ $SPINNER_PID -ne 0 ]]; then
        kill "$SPINNER_PID" &>/dev/null
        wait "$SPINNER_PID" &>/dev/null
        echo -n -e "\r\033[K" # xóa dòng spinner
        SPINNER_PID=0
    fi
    tput cnorm # hiện lại con trỏ
}

# Chạy lệnh ở chế độ im lặng, hiển thị spinner và log lỗi nếu thất bại
run_silent_command() {
  local message="$1"
  local command_to_run="$2"
  local log_file="/tmp/n8n_manager_cmd_$(date +%s%N).log"
  local show_explicit_processing_message="${3:-true}"

  if [[ "$show_explicit_processing_message" == "false" ]]; then
    if sudo bash -c "${command_to_run}" >> "${log_file}" 2>&1; then
      sudo rm -f "${log_file}"
      return 0
    else
      if [[ $SPINNER_PID -ne 0 ]]; then
          stop_spinner
      fi
      echo -e "\n${RED}Lỗi trong khi [${message}] (xử lý ngầm).${NC}"
      echo -e "${RED}Chi tiết lỗi đã được ghi vào: ${log_file}${NC}"
      echo -e "${RED}5 dòng cuối của log:${NC}"
      tail -n 5 "${log_file}" | sed 's/^/    /'
      return 1
    fi
  else
    if [[ $SPINNER_PID -ne 0 ]]; then
        stop_spinner
    fi

    echo -n -e "${CYAN}Xử lý: ${message}... ${NC}"

    if sudo bash -c "${command_to_run}" > "${log_file}" 2>&1; then
      echo -e "${GREEN}Xong.${NC}"
      sudo rm -f "${log_file}"
      return 0
    else
      echo -e "${RED}Thất bại.${NC}"
      echo -e "${RED}Chi tiết lỗi đã được ghi vào: ${log_file}${NC}"
      echo -e "${RED}5 dòng cuối của log:${NC}"
      tail -n 5 "${log_file}" | sed 's/^/    /'
      return 1
    fi
  fi
}

# ---- src/lib/setup.sh ----
# --- Các bước Cài đặt ---

install_prerequisites() {
  start_spinner "Kiểm tra và cài đặt các gói phụ thuộc..."

  run_silent_command "Cập nhật danh sách gói" "apt-get update -y" "false"
  if [ $? -ne 0 ]; then return 1; fi

  if ! is_package_installed nginx; then
    run_silent_command "Cài đặt Nginx" "apt-get install -y nginx" "false"
    if [ $? -ne 0 ]; then return 1; fi
    sudo systemctl enable nginx >/dev/null 2>&1
    sudo systemctl start nginx >/dev/null 2>&1
  fi

  if ! command_exists docker; then
    if ! curl -fsSL https://get.docker.com -o get-docker.sh; then
        echo -e "${RED}Lỗi tải script cài đặt Docker.${NC}"
        return 1
    fi
    run_silent_command "Cài đặt Docker từ script" "sh get-docker.sh" "false"
    if [ $? -ne 0 ]; then rm get-docker.sh; return 1; fi
    sudo usermod -aG docker "$(whoami)" >/dev/null 2>&1
    rm get-docker.sh
  fi

  if docker compose version &>/dev/null; then
    DOCKER_COMPOSE_CMD="docker compose"
  elif command_exists docker-compose; then
    DOCKER_COMPOSE_CMD="docker-compose"
  else
    # Tải phiên bản mới nhất của Docker Compose từ GitHub
    LATEST_COMPOSE_VERSION=$(curl -s https://api.github.com/repos/docker/compose/releases/latest | grep '"tag_name":' | sed -E 's/.*"([^"]+)".*/\1/')
    if [[ -z "$LATEST_COMPOSE_VERSION" ]]; then
        LATEST_COMPOSE_VERSION="1.29.2"
    fi
    run_silent_command "Tải Docker Compose v${LATEST_COMPOSE_VERSION}" \
      "curl -L \"https://github.com/docker/compose/releases/download/${LATEST_COMPOSE_VERSION}/docker-compose-$(uname -s)-$(uname -m)\" -o /usr/local/bin/docker-compose" "false"
    if [ $? -ne 0 ]; then return 1; fi
    sudo chmod +x /usr/local/bin/docker-compose
    DOCKER_COMPOSE_CMD="docker-compose"
  fi

  if ! command_exists certbot; then
    run_silent_command "Cài đặt Certbot và plugin Nginx" "apt-get install -y certbot python3-certbot-nginx" "false"
    if [ $? -ne 0 ]; then return 1; fi
  fi

  if ! command_exists dig; then
    run_silent_command "Cài đặt dnsutils (cho lệnh dig)" "apt-get install -y dnsutils" "false"
    if [ $? -ne 0 ]; then return 1; fi
  fi

  if ! command_exists curl; then
    run_silent_command "Cài đặt curl" "apt-get install -y curl" "false"
    if [ $? -ne 0 ]; then return 1; fi
  fi

  if command_exists ufw; then
    sudo ufw allow http > /dev/null
    sudo ufw allow https > /dev/null
  fi

  stop_spinner
  echo -e "${GREEN}Kiểm tra và cài đặt gói phụ thuộc hoàn tất.${NC}"
}

setup_directories_and_env_file() {
  start_spinner "Thiết lập thư mục và file .env..."
  if [ ! -d "${N8N_DIR}" ]; then
    sudo mkdir -p "${N8N_DIR}"
  fi
  if [ ! -f "${ENV_FILE}" ]; then
    sudo touch "${ENV_FILE}"
    sudo chmod 600 "${ENV_FILE}"  # chỉ root mới đọc được
  fi
  sudo mkdir -p "${NGINX_EXPORT_INCLUDE_DIR}"
  sudo mkdir -p "${TEMPLATE_DIR}"

  stop_spinner
  echo -e "${GREEN}Thiết lập thư mục và file .env hoàn tất.${NC}"
}

get_domain_and_dns_check_reusable() {
  local result_var_name="$1"
  local current_domain_to_avoid="${2:-}"
  local prompt_message="${3:-Nhập tên miền bạn muốn sử dụng cho n8n (ví dụ: n8n.example.com)}"

  trap 'echo -e "\n${YELLOW}Huỷ bỏ nhập tên miền.${NC}"; return 1;' SIGINT SIGTERM

  echo -e "${CYAN}---> Nhập thông tin tên miền (Nhấn Ctrl+C để huỷ)...${NC}"
  local new_domain_input
  local server_ip
  local resolved_ip

  server_ip=$(get_public_ip)
  if [ $? -ne 0 ]; then
    trap - SIGINT SIGTERM
    return 1
  fi

  echo -e "Địa chỉ IP public của server là: ${GREEN}${server_ip}${NC}"

  while true; do
    local prompt_string
    prompt_string=$(echo -e "${prompt_message}: ")
    echo -n "$prompt_string"

    if ! read -r new_domain_input; then
        echo -e "\n${YELLOW}Huỷ bỏ nhập tên miền.${NC}"
        trap - SIGINT SIGTERM
        return 1
    fi

    if [[ -z "$new_domain_input" ]]; then
      echo -e "${RED}Tên miền không được để trống. Vui lòng nhập lại.${NC}"
      continue
    fi

    if [[ -n "$current_domain_to_avoid" && "$new_domain_input" == "$current_domain_to_avoid" ]]; then
      echo -e "${YELLOW}Tên miền mới (${new_domain_input}) trùng với tên miền hiện tại (${current_domain_to_avoid}).${NC}"
      echo -e "${YELLOW}Vui lòng nhập một tên miền khác.${NC}"
      continue
    fi

    start_spinner "Kiểm tra DNS cho ${new_domain_input}..."
    resolved_ip=$(timeout 5 dig +short A "$new_domain_input" @1.1.1.1 | tail -n1)
    if [[ -z "$resolved_ip" ]]; then
        # Thử tra cứu CNAME nếu không có bản ghi A
        local cname_target
        cname_target=$(timeout 5 dig +short CNAME "$new_domain_input" @1.1.1.1 | tail -n1)
        if [[ -n "$cname_target" ]]; then
             resolved_ip=$(timeout 5 dig +short A "$cname_target" @1.1.1.1 | tail -n1)
        fi
    fi
    stop_spinner

    if [[ "$resolved_ip" == "$server_ip" ]]; then
      echo -e "${GREEN}DNS cho ${new_domain_input} đã được trỏ về IP server chính xác (${resolved_ip}).${NC}"
      printf -v "$result_var_name" "%s" "$new_domain_input"
      trap - SIGINT SIGTERM
      break
    else
      echo -e "${RED}Lỗi: Tên miền ${new_domain_input} (trỏ về ${resolved_ip:-'không tìm thấy bản ghi A/CNAME hoặc timeout'}) chưa được trỏ về IP server (${server_ip}).${NC}"
      echo -e "${YELLOW}Vui lòng trỏ DNS A record của tên miền ${new_domain_input} về địa chỉ IP ${server_ip} và đợi DNS cập nhật.${NC}"

      trap 'echo -e "\n${YELLOW}Huỷ bỏ nhập tên miền.${NC}"; return 1;' SIGINT SIGTERM
      local choice_prompt
      choice_prompt=$(echo -e "Nhấn Enter để kiểm tra lại, hoặc '${CYAN}s${NC}' để bỏ qua, '${CYAN}0${NC}' để huỷ bỏ: ")
      echo -n "$choice_prompt"
      if ! read -r dns_choice; then
          echo -e "\n${YELLOW}Huỷ bỏ nhập lựa chọn.${NC}"
          trap - SIGINT SIGTERM
          return 1
      fi

      if [[ "$dns_choice" == "s" || "$dns_choice" == "S" ]]; then
        echo -e "${YELLOW}Bỏ qua kiểm tra DNS. Đảm bảo bạn đã trỏ DNS chính xác.${NC}"
        printf -v "$result_var_name" "%s" "$new_domain_input"
        trap - SIGINT SIGTERM
        break
      elif [[ "$dns_choice" == "0" ]]; then
        echo -e "${YELLOW}Huỷ bỏ nhập tên miền.${NC}"
        trap - SIGINT SIGTERM
        return 1
      fi
    fi
  done
  trap - SIGINT SIGTERM
  return 0
}

prompt_database_configuration() {
  local db_type="local"
  if [[ "$NON_INTERACTIVE" == "true" && -n "$CLI_EXTERNAL_DB" ]]; then
    db_type="external"
  elif [[ "$NON_INTERACTIVE" != "true" ]]; then
    echo -e "\n${CYAN}--- Cấu hình Database & Redis ---${NC}"
    echo -e "1) Cài đặt Database Local (Tự động cấp phát Postgres & Redis qua Docker)"
    echo -e "2) Sử dụng Database External (Supabase, AWS RDS, Redis Cloud...)"
    local db_choice
    read -p "Nhập lựa chọn của bạn (1-2) [Mặc định: 1]: " db_choice
    if [[ "$db_choice" == "2" ]]; then
      db_type="external"
    fi
  fi

  update_env_file "DB_SETUP_TYPE" "$db_type"

  if [[ "$db_type" == "external" ]]; then
    if [[ "$NON_INTERACTIVE" == "true" ]]; then
      update_env_file "POSTGRES_HOST" "${CLI_DB_HOST:-}"
      update_env_file "POSTGRES_PORT" "${CLI_DB_PORT:-5432}"
      update_env_file "POSTGRES_DB" "${CLI_DB_NAME:-}"
      update_env_file "POSTGRES_USER" "${CLI_DB_USER:-}"
      update_env_file "POSTGRES_PASSWORD" "${CLI_DB_PASSWORD:-}"
      update_env_file "REDIS_HOST" "${CLI_REDIS_HOST:-}"
      update_env_file "REDIS_PORT" "${CLI_REDIS_PORT:-6379}"
      update_env_file "REDIS_PASSWORD" "${CLI_REDIS_PASSWORD:-}"
    else
      echo -e "\n${CYAN}[1/2] Cấu hình PostgreSQL External${NC}"
      local pg_host pg_port pg_db pg_user pg_pass
      read -p "Host (VD: db.supabase.co): " pg_host
      read -p "Port [5432]: " pg_port
      pg_port=${pg_port:-5432}
      read -p "Database Name: " pg_db
      read -p "User: " pg_user
      read -p "Password: " -s pg_pass
      echo ""

      echo -e "\n${CYAN}[2/2] Cấu hình Redis External (Tuỳ chọn)${NC}"
      local redis_host redis_port redis_pass
      read -p "Host (Để rỗng nếu không dùng Redis): " redis_host
      if [[ -n "$redis_host" ]]; then
        read -p "Port [6379]: " redis_port
        redis_port=${redis_port:-6379}
        read -p "Password: " -s redis_pass
        echo ""
      fi

      update_env_file "POSTGRES_HOST" "$pg_host"
      update_env_file "POSTGRES_PORT" "$pg_port"
      update_env_file "POSTGRES_DB" "$pg_db"
      update_env_file "POSTGRES_USER" "$pg_user"
      update_env_file "POSTGRES_PASSWORD" "$pg_pass"
      if [[ -n "$redis_host" ]]; then
        update_env_file "REDIS_HOST" "$redis_host"
        update_env_file "REDIS_PORT" "$redis_port"
        update_env_file "REDIS_PASSWORD" "$redis_pass"
      fi
    fi
  fi
}

generate_credentials() {
  start_spinner "Tạo thông tin đăng nhập và cấu hình..."
  update_env_file "N8N_ENCRYPTION_KEY" "$(generate_random_string 64)"

  local system_timezone
  system_timezone=$(timedatectl show --property=Timezone --value 2>/dev/null)
  update_env_file "GENERIC_TIMEZONE" "${system_timezone:-Asia/Ho_Chi_Minh}"

  local db_setup_type
  if [ -f "${ENV_FILE}" ]; then
    db_setup_type=$(grep "^DB_SETUP_TYPE=" "${ENV_FILE}" | cut -d'=' -f2)
  fi

  if [[ "$db_setup_type" != "external" ]]; then
    update_env_file "POSTGRES_DB" "n8n_db_$(generate_random_string 6 | tr '[:upper:]' '[:lower:]')"
    update_env_file "POSTGRES_USER" "n8n_user_$(generate_random_string 8 | tr '[:upper:]' '[:lower:]')"
    update_env_file "POSTGRES_PASSWORD" "$(generate_random_string 32)"

    update_env_file "REDIS_PASSWORD" "$(generate_random_string 32)"
  fi

  stop_spinner
  echo -e "${GREEN}Thông tin đăng nhập và cấu hình đã được lưu vào ${ENV_FILE}.${NC}"
  echo -e "${YELLOW}Quan trọng: Vui lòng sao lưu file ${ENV_FILE}.${NC}"
}

create_docker_compose_config() {
  start_spinner "Tạo file docker-compose.yml..."
  local n8n_encryption_key_val postgres_user_val postgres_password_val postgres_db_val postgres_host_val postgres_port_val redis_password_val redis_host_val redis_port_val db_setup_type_val
  local domain_name_val generic_timezone_val

  if [ -f "${ENV_FILE}" ]; then
    n8n_encryption_key_val=$(grep "^N8N_ENCRYPTION_KEY=" "${ENV_FILE}" | cut -d'=' -f2)
    postgres_user_val=$(grep "^POSTGRES_USER=" "${ENV_FILE}" | cut -d'=' -f2)
    postgres_password_val=$(grep "^POSTGRES_PASSWORD=" "${ENV_FILE}" | cut -d'=' -f2)
    postgres_db_val=$(grep "^POSTGRES_DB=" "${ENV_FILE}" | cut -d'=' -f2)
    postgres_host_val=$(grep "^POSTGRES_HOST=" "${ENV_FILE}" | cut -d'=' -f2)
    postgres_port_val=$(grep "^POSTGRES_PORT=" "${ENV_FILE}" | cut -d'=' -f2)
    redis_password_val=$(grep "^REDIS_PASSWORD=" "${ENV_FILE}" | cut -d'=' -f2)
    redis_host_val=$(grep "^REDIS_HOST=" "${ENV_FILE}" | cut -d'=' -f2)
    redis_port_val=$(grep "^REDIS_PORT=" "${ENV_FILE}" | cut -d'=' -f2)
    domain_name_val=$(grep "^DOMAIN_NAME=" "${ENV_FILE}" | cut -d'=' -f2)
    generic_timezone_val=$(grep "^GENERIC_TIMEZONE=" "${ENV_FILE}" | cut -d'=' -f2)
    db_setup_type_val=$(grep "^DB_SETUP_TYPE=" "${ENV_FILE}" | cut -d'=' -f2)
  fi

  local n8n_db_host="postgres"
  local n8n_db_port="5432"

  if [[ "$db_setup_type_val" == "external" ]]; then
    n8n_db_host="${postgres_host_val}"
    n8n_db_port="${postgres_port_val}"
  fi

  local services_postgres=""
  local services_redis=""
  local volumes_postgres=""
  local volumes_redis=""
  local n8n_depends_on=""

  if [[ "$db_setup_type_val" != "external" ]]; then
services_postgres="
  postgres:
    image: postgres:15-alpine
    restart: always
    container_name: n8n_postgres
    environment:
      - POSTGRES_USER=\${POSTGRES_USER:-${postgres_user_val}}
      - POSTGRES_PASSWORD=\${POSTGRES_PASSWORD:-${postgres_password_val}}
      - POSTGRES_DB=\${POSTGRES_DB:-${postgres_db_val}}
    volumes:
      - postgres_data:/var/lib/postgresql/data
    healthcheck:
      test: [\"CMD-SHELL\", \"pg_isready -U \${POSTGRES_USER:-${postgres_user_val}} -d \${POSTGRES_DB:-${postgres_db_val}}\"]
      interval: 10s
      timeout: 5s
      retries: 5
    logging:
      driver: \"json-file\"
      options:
        max-size: \"10m\"
        max-file: \"3\"
"
services_redis="
  redis:
    image: redis:7-alpine
    restart: always
    container_name: n8n_redis
    command: redis-server --save 60 1 --loglevel warning --requirepass \${REDIS_PASSWORD:-${redis_password_val}}
    ports:
      - \"127.0.0.1:6379:6379\"
    volumes:
      - redis_data:/data
    healthcheck:
      test: [\"CMD\", \"redis-cli\", \"-a\", \"\${REDIS_PASSWORD:-${redis_password_val}}\", \"ping\"]
      interval: 10s
      timeout: 5s
      retries: 5
    logging:
      driver: \"json-file\"
      options:
        max-size: \"10m\"
        max-file: \"3\"
"
volumes_postgres="  postgres_data:"
volumes_redis="  redis_data:"
n8n_depends_on="
    depends_on:
      postgres:
        condition: service_healthy
      redis:
        condition: service_healthy"
  fi

  sudo bash -c "cat > ${DOCKER_COMPOSE_FILE}" <<EOF
# version: '3.8'

services:${services_postgres}${services_redis}
  ${N8N_SERVICE_NAME}:
    image: n8nio/n8n:latest
    restart: always
    container_name: ${N8N_CONTAINER_NAME}
    ports:
      - "127.0.0.1:5678:5678"
    environment:
      - DB_TYPE=postgresdb
      - DB_POSTGRESDB_HOST=\${POSTGRES_HOST:-${n8n_db_host}}
      - DB_POSTGRESDB_PORT=\${POSTGRES_PORT:-${n8n_db_port}}
      - DB_POSTGRESDB_DATABASE=\${POSTGRES_DB:-${postgres_db_val}}
      - DB_POSTGRESDB_USER=\${POSTGRES_USER:-${postgres_user_val}}
      - DB_POSTGRESDB_PASSWORD=\${POSTGRES_PASSWORD:-${postgres_password_val}}
      - N8N_ENCRYPTION_KEY=\${N8N_ENCRYPTION_KEY:-${n8n_encryption_key_val}}
      - GENERIC_TIMEZONE=\${GENERIC_TIMEZONE:-${generic_timezone_val}}
      - N8N_HOST=\${DOMAIN_NAME:-${domain_name_val}}
      - N8N_PORT=5678
      - N8N_PROTOCOL=https
      - NODE_ENV=production
      - WEBHOOK_URL=https://\${DOMAIN_NAME:-${domain_name_val}}/
      - N8N_ENFORCE_SETTINGS_FILE_PERMISSIONS=true
      - N8N_BASIC_AUTH_ACTIVE=false
      - N8N_RUNNERS_ENABLED=true
    volumes:
      - n8n_data:/home/node/.n8n${n8n_depends_on}
    logging:
      driver: "json-file"
      options:
        max-size: "10m"
        max-file: "3"

volumes:
${volumes_postgres}
${volumes_redis}
  n8n_data:
EOF
  stop_spinner
}

start_docker_containers() {
  start_spinner "Khởi chạy N8N Cloud..."
  cd "${N8N_DIR}" || { return 1; }

  run_silent_command "Tải Docker images" "$DOCKER_COMPOSE_CMD pull" "false"

  run_silent_command "Khởi chạy container qua docker-compose" "$DOCKER_COMPOSE_CMD up -d --force-recreate" "false"
  if [ $? -ne 0 ]; then return 1; fi

  # Chờ container sẵn sàng bằng cách polling healthcheck thay vì sleep cố định
  local max_wait=60
  local elapsed=0
  local interval=3
  stop_spinner
  echo -n -e "${CYAN}Chờ container N8N khởi động${NC}"
  while [[ $elapsed -lt $max_wait ]]; do
    local health
    health=$(sudo docker inspect --format='{{.State.Health.Status}}' "${N8N_CONTAINER_NAME}" 2>/dev/null || echo "")
    if [[ "$health" == "healthy" ]] || sudo docker exec "${N8N_CONTAINER_NAME}" echo "" &>/dev/null 2>&1; then
      echo -e " ${GREEN}OK${NC}"
      break
    fi
    echo -n "."
    sleep $interval
    elapsed=$((elapsed + interval))
  done
  if [[ $elapsed -ge $max_wait ]]; then
    echo -e " ${YELLOW}(timeout — container có thể vẫn đang khởi động)${NC}"
  fi

  echo -e "${GREEN}N8N Cloud đã khởi chạy.${NC}"
  cd - > /dev/null
}

configure_nginx_and_ssl() {
  start_spinner "Cấu hình Nginx và SSL với Certbot..."
  local domain_name
  local user_email
  domain_name=$(grep "^DOMAIN_NAME=" "${ENV_FILE}" | cut -d'=' -f2)
  user_email=$(grep "^LETSENCRYPT_EMAIL=" "${ENV_FILE}" | cut -d'=' -f2)
  local webroot_path="/var/www/html"

  if [[ -z "$domain_name" || -z "$user_email" ]]; then
    echo -e "${RED}Không tìm thấy DOMAIN_NAME hoặc LETSENCRYPT_EMAIL trong file .env.${NC}"
    return 1
  fi

  local nginx_conf_file="/etc/nginx/sites-available/${domain_name}.conf"

  sudo mkdir -p "${webroot_path}/.well-known/acme-challenge"
  sudo chown www-data:www-data "${webroot_path}" -R

  # Tạo cấu hình Nginx tạm để Let's Encrypt xác minh qua HTTP
  run_silent_command "Tạo cấu hình Nginx ban đầu cho HTTP challenge" \
    "bash -c \"cat > ${nginx_conf_file}\" <<EOF
server {
    listen 80;
    server_name ${domain_name};

    location /.well-known/acme-challenge/ {
        root ${webroot_path};
        allow all;
    }
}
EOF" "false" || return 1

  sudo ln -sfn "${nginx_conf_file}" "/etc/nginx/sites-enabled/${domain_name}.conf"

  run_silent_command "Kiểm tra cấu hình Nginx HTTP" "nginx -t" "false" || return 1

  sudo systemctl reload nginx >/dev/null 2>&1

  if ! sudo certbot certonly --webroot -w "${webroot_path}" -d "${domain_name}" \
        --agree-tos --email "${user_email}" --non-interactive --quiet \
        --preferred-challenges http > /tmp/certbot_obtain.log 2>&1; then
    echo -e "${RED}Lấy chứng chỉ SSL thất bại.${NC}"
    echo -e "${YELLOW}Kiểm tra log Certbot tại /var/log/letsencrypt/ và /tmp/certbot_obtain.log.${NC}"
    return 1
  fi

  sudo mkdir -p /etc/letsencrypt
  if [ ! -f /etc/letsencrypt/options-ssl-nginx.conf ]; then
    run_silent_command "Tải tuỳ chọn SSL của Let's Encrypt" \
    "curl -s https://raw.githubusercontent.com/certbot/certbot/master/certbot-nginx/certbot_nginx/_internal/tls_configs/options-ssl-nginx.conf -o /etc/letsencrypt/options-ssl-nginx.conf" "false" || return 1
  fi
  if [ ! -f /etc/letsencrypt/ssl-dhparams.pem ]; then
    run_silent_command "Tạo tham số SSL DH (2048-bit)" "openssl dhparam -out /etc/letsencrypt/ssl-dhparams.pem 2048" "false" || return 1
  fi

  # Tạo cấu hình Nginx hoàn chỉnh với SSL, proxy pass và security headers
  run_silent_command "Tạo cấu hình Nginx cuối cùng với SSL và proxy" \
  "bash -c \"cat > ${nginx_conf_file}\" <<EOF
server {
    listen 80;
    server_name ${domain_name};

    location /.well-known/acme-challenge/ {
        root ${webroot_path};
        allow all;
    }

    location / {
        return 301 https://\\\$host\\\$request_uri;
    }
}

server {
    listen 443 ssl http2;
    server_name ${domain_name};

    ssl_certificate /etc/letsencrypt/live/${domain_name}/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/${domain_name}/privkey.pem;

    include /etc/letsencrypt/options-ssl-nginx.conf;
    ssl_dhparam /etc/letsencrypt/ssl-dhparams.pem;

    location /.well-known/acme-challenge/ {
        root ${webroot_path};
        allow all;
    }

    include ${NGINX_EXPORT_INCLUDE_DIR}/${NGINX_EXPORT_INCLUDE_FILE_BASENAME}_*.conf;

    add_header X-Frame-Options \"SAMEORIGIN\" always;
    add_header X-XSS-Protection \"1; mode=block\" always;
    add_header X-Content-Type-Options \"nosniff\" always;
    add_header Referrer-Policy \"strict-origin-when-cross-origin\" always;
    add_header Strict-Transport-Security \"max-age=31536000; includeSubDomains; preload\" always;

    client_max_body_size 100M;

    access_log /var/log/nginx/${domain_name}.access.log;
    error_log /var/log/nginx/${domain_name}.error.log;

    location / {
        proxy_pass http://127.0.0.1:5678;
        proxy_set_header Host \\\$host;
        proxy_set_header X-Real-IP \\\$remote_addr;
        proxy_set_header X-Forwarded-For \\\$proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto \\\$scheme;

        proxy_http_version 1.1;
        proxy_set_header Upgrade \\\$http_upgrade;
        proxy_set_header Connection 'upgrade';

        proxy_buffering off;
        proxy_cache off;
        proxy_read_timeout 7200s;
        proxy_send_timeout 7200s;
    }

    location ~ /\\\\. {
        deny all;
    }
}
EOF" "false" || return 1

  if [ ! -f "${NGINX_EXPORT_INCLUDE_DIR}/${NGINX_EXPORT_INCLUDE_FILE_BASENAME}.conf" ]; then
    sudo touch "${NGINX_EXPORT_INCLUDE_DIR}/${NGINX_EXPORT_INCLUDE_FILE_BASENAME}.conf"
  fi

  run_silent_command "Kiểm tra cấu hình Nginx cuối cùng" "nginx -t" "false" || return 1

  sudo systemctl reload nginx >/dev/null 2>&1

  # Bật tự động gia hạn SSL qua systemd timer
  if ! sudo systemctl list-timers | grep -q 'certbot.timer'; then
      sudo systemctl enable certbot.timer >/dev/null 2>&1
      sudo systemctl start certbot.timer >/dev/null 2>&1
  fi
  run_silent_command "Kiểm tra gia hạn SSL (dry-run)" "certbot renew --dry-run" "false"

  stop_spinner
  echo -e "${GREEN}Cấu hình Nginx và SSL hoàn tất.${NC}"
}

final_checks_and_message() {
  start_spinner "Thực hiện kiểm tra cuối cùng..."
  local domain_name
  domain_name=$(grep "^DOMAIN_NAME=" "${ENV_FILE}" | cut -d'=' -f2)

  sleep 10  # đợi N8N hoàn toàn sẵn sàng sau khi Nginx reload

  local http_status
  http_status=$(curl -L -s -o /dev/null -w "%{http_code}" "https://${domain_name}")

  stop_spinner

  if [[ "$http_status" == "200" ]]; then
    echo -e "${GREEN}N8N Cloud đã được cài đặt thành công!${NC}"
    echo -e "Bạn có thể truy cập n8n tại: ${GREEN}https://${domain_name}${NC}"
  else
    echo -e "${RED}Lỗi! Không thể truy cập n8n tại https://${domain_name} (HTTP Status: ${http_status}).${NC}"
    echo -e "${YELLOW}Vui lòng kiểm tra các bước sau:${NC}"
    echo -e "  1. Log Docker của container n8n: sudo ${DOCKER_COMPOSE_CMD} -f ${DOCKER_COMPOSE_FILE} logs ${N8N_CONTAINER_NAME}"
    echo -e "  2. Log Nginx: sudo tail -n 50 /var/log/nginx/${domain_name}.error.log"
    echo -e "  3. Trạng thái Certbot: sudo certbot certificates"
    echo -e "  4. Đảm bảo DNS đã trỏ đúng và không có firewall nào chặn port 80/443."
    return 1
  fi

  echo -e "${YELLOW}Quan trọng: Hãy lưu trữ file ${ENV_FILE} ở một nơi an toàn!${NC}"
  echo -e "Bạn nên tạo user đầu tiên cho n8n ngay sau khi truy cập."
}

# ---- src/lib/features/install.sh ----
# --- Hàm chính để Cài đặt N8N ---
install() {
  check_root
  if [ -d "${N8N_DIR}" ] && [ -f "${DOCKER_COMPOSE_FILE}" ]; then
    echo -e "\n${YELLOW}[CẢNH BÁO] Phát hiện thư mục ${N8N_DIR} và file ${DOCKER_COMPOSE_FILE} đã tồn tại.${NC}"
    local existing_containers
    if command_exists $DOCKER_COMPOSE_CMD && [ -f "${DOCKER_COMPOSE_FILE}" ]; then
        pushd "${N8N_DIR}" > /dev/null || { echo -e "${RED}Không thể truy cập thư mục ${N8N_DIR}${NC}"; return 1; }
        existing_containers=$(sudo $DOCKER_COMPOSE_CMD ps -q 2>/dev/null)
        popd > /dev/null
    fi

    if [[ -n "$existing_containers" ]] || [ -f "${DOCKER_COMPOSE_FILE}" ]; then
        echo -e "${YELLOW}    Có vẻ như N8N đã được cài đặt hoặc đã có một phần cấu hình trước đó.${NC}"
        echo -e "${YELLOW}    Nếu bạn muốn cài đặt lại từ đầu, vui lòng chọn mục '9) Xóa N8N và cài đặt lại' từ menu chính.${NC}"
        echo -e "${YELLOW}    Nhấn Enter để quay lại menu chính...${NC}"
        read -r
        return 0
    fi
  fi

  echo -e "\n${CYAN}===================================================${NC}"
  echo -e "${CYAN}    Bắt đầu quá trình cài đặt N8N Cloud - BMSG        ${NC}"
  echo -e "${CYAN}===================================================${NC}\n"

  trap 'RC=$?; stop_spinner; if [[ $RC -ne 0 && $RC -ne 130 ]]; then echo -e "\n${RED}Đã xảy ra lỗi trong quá trình cài đặt (Mã lỗi: $RC).${NC}"; fi; read -r -p "Nhấn Enter để quay lại menu..."; return 0;' ERR SIGINT SIGTERM

  install_prerequisites
  setup_directories_and_env_file

  local domain_name_for_install
  if [[ "$NON_INTERACTIVE" == "true" && -n "$CLI_DOMAIN" ]]; then
    domain_name_for_install="$CLI_DOMAIN"
  else
    if ! get_domain_and_dns_check_reusable domain_name_for_install "" "Nhập tên miền bạn muốn sử dụng cho N8N"; then
      return 0
    fi
  fi
  update_env_file "DOMAIN_NAME" "$domain_name_for_install"

  # Hỏi email thực để nhận thông báo khi chứng chỉ SSL sắp hết hạn
  local letsencrypt_email
  if [[ "$NON_INTERACTIVE" == "true" && -n "$CLI_EMAIL" ]]; then
    letsencrypt_email="$CLI_EMAIL"
  elif [[ "$NON_INTERACTIVE" == "true" && -z "$CLI_EMAIL" ]]; then
    letsencrypt_email="admin@${domain_name_for_install}"
  else
    while true; do
      echo -n -e "${CYAN}Nhập email để nhận thông báo SSL (Let's Encrypt): ${NC}"
      read -r letsencrypt_email
      if [[ -z "$letsencrypt_email" ]]; then
        echo -e "${RED}Email không được để trống.${NC}"
      elif [[ ! "$letsencrypt_email" =~ ^[^@]+@[^@]+\.[^@]+$ ]]; then
        echo -e "${RED}Email không hợp lệ. Vui lòng nhập lại.${NC}"
      else
        break
      fi
    done
  fi
  update_env_file "LETSENCRYPT_EMAIL" "$letsencrypt_email"

  prompt_database_configuration
  generate_credentials
  create_docker_compose_config
  start_docker_containers
  configure_nginx_and_ssl
  final_checks_and_message

  trap - ERR SIGINT SIGTERM

  echo -e "\n${GREEN}===================================================${NC}"
  echo -e "${GREEN}      Hoàn tất quá trình cài đặt N8N Cloud!       ${NC}"
  echo -e "${GREEN}===================================================${NC}\n"
  
  if [[ "$NON_INTERACTIVE" != "true" ]]; then
    echo -e "${YELLOW}Nhấn Enter để quay lại menu chính...${NC}"
    read -r
  fi
}

# --- Hàm Xóa N8N và Cài đặt lại ---
reinstall_n8n() {
    check_root
    echo -e "\n${RED}======================= CẢNH BÁO XÓA DỮ LIỆU =======================${NC}"
    echo -e "${YELLOW}Bạn đã chọn chức năng XÓA TOÀN BỘ N8N và CÀI ĐẶT LẠI.${NC}"
    echo -e "${RED}HÀNH ĐỘNG NÀY SẼ XÓA VĨNH VIỄN:${NC}"
    echo -e "${RED}  - Toàn bộ dữ liệu n8n (workflows, credentials, executions,...).${NC}"
    echo -e "${RED}  - Database PostgreSQL của n8n.${NC}"
    echo -e "${RED}  - Dữ liệu cache Redis (nếu có).${NC}"
    echo -e "${RED}  - Cấu hình Nginx và SSL cho tên miền hiện tại của n8n.${NC}"
    echo -e "${RED}  - Toàn bộ thư mục cài đặt ${N8N_DIR}.${NC}"
    echo -e "\n${YELLOW}ĐỀ NGHỊ: Nếu bạn có dữ liệu quan trọng, hãy sử dụng chức năng${NC}"
    echo -e "${YELLOW}  '6) Export tất cả (workflow & credentials)'${NC}"
    echo -e "${YELLOW}để SAO LƯU dữ liệu trước khi tiếp tục.${NC}"
    echo -e "${RED}Hành động này KHÔNG THỂ HOÀN TÁC.${NC}"

    local confirm_prompt
    confirm_prompt=$(echo -e "${YELLOW}Nhập '${NC}${RED}delete${NC}${YELLOW}' để xác nhận xóa, hoặc nhập '${NC}${CYAN}0${NC}${YELLOW}' để quay lại menu: ${NC}")
    local confirmation
    echo -n "$confirm_prompt"
    read -r confirmation

    if [[ "$confirmation" == "0" ]]; then
        echo -e "\n${GREEN}Huỷ bỏ thao tác. Quay lại menu chính...${NC}"
        sleep 1
        return 0
    elif [[ "$confirmation" != "delete" ]]; then
        echo -e "\n${RED}Xác nhận không hợp lệ. Huỷ bỏ thao tác.${NC}"
        echo -e "${YELLOW}Nhấn Enter để quay lại menu chính...${NC}"
        read -r
        return 0
    fi

    echo -e "\n${CYAN}Bắt đầu quá trình xóa N8N...${NC}"
    trap 'stop_spinner; echo -e "\n${RED}Đã xảy ra lỗi hoặc huỷ bỏ trong quá trình xóa N8N.${NC}"; read -r -p "Nhấn Enter để quay lại menu..."; return 0;' ERR SIGINT SIGTERM

    start_spinner "Đang xóa N8N..."

    if [ -d "${N8N_DIR}" ]; then
        if [ -f "${DOCKER_COMPOSE_FILE}" ]; then
            stop_spinner
            start_spinner "Đang tiến hành xóa dữ liệu..."
            pushd "${N8N_DIR}" > /dev/null || { stop_spinner; echo -e "${RED}Lỗi: Không thể truy cập ${N8N_DIR}.${NC}"; return 1; }
            if ! sudo $DOCKER_COMPOSE_CMD down -v --remove-orphans > /tmp/n8n_reinstall_docker_down.log 2>&1; then
                stop_spinner
                echo -e "${RED}Lỗi khi dừng/xóa Docker. Kiểm tra /tmp/n8n_reinstall_docker_down.log.${NC}"
            fi
            popd > /dev/null
            stop_spinner
            start_spinner "Tiếp tục xóa N8N..."
        else
            echo -e "\r\033[K ${YELLOW}Không tìm thấy file ${DOCKER_COMPOSE_FILE}. Bỏ qua bước xóa Docker.${NC}"
        fi

        local domain_to_remove
        if [ -f "${ENV_FILE}" ]; then
            domain_to_remove=$(grep "^DOMAIN_NAME=" "${ENV_FILE}" | cut -d'=' -f2)
        fi

        if [[ -n "$domain_to_remove" ]]; then
            local nginx_conf_avail="/etc/nginx/sites-available/${domain_to_remove}.conf"
            local nginx_conf_enabled="/etc/nginx/sites-enabled/${domain_to_remove}.conf"

            if [ -f "$nginx_conf_avail" ] || [ -L "$nginx_conf_enabled" ]; then
                 stop_spinner
                 start_spinner "Xóa cấu hình Nginx cho ${domain_to_remove}..."
                 sudo rm -f "$nginx_conf_avail"
                 sudo rm -f "$nginx_conf_enabled"
                 sudo systemctl reload nginx > /tmp/n8n_reinstall_nginx_reload.log 2>&1
                 stop_spinner
                 start_spinner "Tiếp tục xóa N8N..."
            fi

            stop_spinner
            start_spinner "Xóa chứng chỉ SSL cho ${domain_to_remove} (nếu có)..."
            if sudo certbot certificates -d "${domain_to_remove}" 2>/dev/null | grep -q "Certificate Name:"; then
                 local cert_name_to_delete
                 cert_name_to_delete=$(sudo certbot certificates -d "${domain_to_remove}" 2>/dev/null | grep "Certificate Name:" | head -n 1 | awk '{print $3}')
                 if [[ -n "$cert_name_to_delete" ]]; then
                    if ! sudo certbot delete --cert-name "${cert_name_to_delete}" --non-interactive > /tmp/n8n_reinstall_cert_delete.log 2>&1; then
                        stop_spinner
                        echo -e "${RED}Lỗi khi xóa chứng chỉ SSL. Kiểm tra /tmp/n8n_reinstall_cert_delete.log.${NC}"
                    else
                        stop_spinner
                    fi
                 else
                    stop_spinner
                    echo -e "${YELLOW}Không thể xác định tên chứng chỉ SSL cho ${domain_to_remove}.${NC}"
                 fi
            else
                 stop_spinner
                 echo -e "${YELLOW}Không tìm thấy chứng chỉ SSL cho ${domain_to_remove} để xóa.${NC}"
            fi
            start_spinner "Tiếp tục xóa N8N..."
        else
             echo -e "\r\033[K ${YELLOW}Không tìm thấy tên miền trong ${ENV_FILE}. Bỏ qua xóa Nginx/SSL.${NC}"
        fi

        if [ -d "${NGINX_EXPORT_INCLUDE_DIR}" ]; then
            stop_spinner; start_spinner "Xóa thư mục cấu hình export Nginx tạm thời..."
            sudo rm -rf "${NGINX_EXPORT_INCLUDE_DIR}"
            stop_spinner; start_spinner "Tiếp tục xóa N8N..."
        fi

        stop_spinner
        start_spinner "Xóa thư mục cài đặt ${N8N_DIR}..."
        if ! sudo rm -rf "${N8N_DIR}"; then
            stop_spinner
            echo -e "${RED}Lỗi khi xóa thư mục ${N8N_DIR}.${NC}"
        else
            stop_spinner
        fi
    else
        echo -e "\r\033[K ${YELLOW}Thư mục ${N8N_DIR} không tồn tại. Bỏ qua bước xóa.${NC}"
    fi

    stop_spinner
    echo -e "${GREEN}Quá trình gỡ cài đặt và xóa dữ liệu N8N hoàn tất.${NC}"
    echo -e "\n${CYAN}Tiến hành cài đặt lại N8N...${NC}"

    trap - ERR SIGINT SIGTERM

    install
}

# ---- src/lib/features/domain.sh ----
# --- Hàm Thay đổi tên miền ---
change_domain() {
    check_root
    echo -e "\n${CYAN}--- Thay Đổi Tên Miền cho N8N ---${NC}"

    if [[ ! -f "${ENV_FILE}" || ! -f "${DOCKER_COMPOSE_FILE}" ]]; then
        echo -e "${RED}Lỗi: Không tìm thấy file cấu hình ${ENV_FILE} hoặc ${DOCKER_COMPOSE_FILE}.${NC}"
        echo -e "${YELLOW}Có vẻ như N8N chưa được cài đặt. Vui lòng cài đặt trước.${NC}"
        read -r -p "Nhấn Enter để quay lại menu..."
        return 0
    fi

    local old_domain_name
    old_domain_name=$(grep "^DOMAIN_NAME=" "${ENV_FILE}" | cut -d'=' -f2)
    if [[ -z "$old_domain_name" ]]; then
        echo -e "${RED}Lỗi: Không tìm thấy DOMAIN_NAME trong file ${ENV_FILE}.${NC}"
        read -r -p "Nhấn Enter để quay lại menu..."
        return 0
    fi
    echo -e "Tên miền hiện tại của N8N là: ${GREEN}${old_domain_name}${NC}"

    local new_domain_for_change
    if ! get_domain_and_dns_check_reusable new_domain_for_change "$old_domain_name" "Nhập tên miền MỚI bạn muốn sử dụng"; then
        read -r -p "Nhấn Enter để quay lại menu..."
        return 0
    fi

    local confirmation_prompt
    confirmation_prompt=$(echo -e "\n${YELLOW}Bạn có chắc chắn muốn thay đổi tên miền từ ${RED}${old_domain_name}${NC} sang ${GREEN}${new_domain_for_change}${NC} không?${NC}\n${RED}Hành động này sẽ yêu cầu cấp lại SSL và khởi động lại các service.${NC}\nNhập '${GREEN}ok${NC}' để xác nhận, hoặc bất kỳ phím nào khác để huỷ bỏ: ")
    local confirmation
    read -r -p "$confirmation_prompt" confirmation

    if [[ "$confirmation" != "ok" ]]; then
        echo -e "\n${GREEN}Huỷ bỏ thay đổi tên miền.${NC}"
        read -r -p "Nhấn Enter để quay lại menu..."
        return 0
    fi

    trap 'RC=$?; stop_spinner; if [[ $RC -ne 0 && $RC -ne 130 ]]; then echo -e "\n${RED}Đã xảy ra lỗi trong quá trình thay đổi tên miền (Mã lỗi: $RC).${NC}"; update_env_file "DOMAIN_NAME" "$old_domain_name"; update_env_file "LETSENCRYPT_EMAIL" "no-reply@${old_domain_name}"; echo -e "${YELLOW}Đã khôi phục tên miền cũ trong .env.${NC}"; fi; read -r -p "Nhấn Enter để quay lại menu..."; return 0;' ERR SIGINT SIGTERM

    start_spinner "Đang thay đổi tên miền..."

    stop_spinner; start_spinner "Cập nhật file .env với tên miền mới..."
    if ! update_env_file "DOMAIN_NAME" "$new_domain_for_change"; then return 1; fi
    if ! update_env_file "LETSENCRYPT_EMAIL" "no-reply@${new_domain_for_change}"; then return 1; fi
    stop_spinner; start_spinner "Tiếp tục thay đổi tên miền..."

    stop_spinner; start_spinner "Dừng service N8N..."
    if ! sudo $DOCKER_COMPOSE_CMD -f "${DOCKER_COMPOSE_FILE}" stop ${N8N_SERVICE_NAME} > /tmp/n8n_change_domain_stop.log 2>&1; then
        echo -e "\n${YELLOW}Cảnh báo: Không thể dừng service ${N8N_SERVICE_NAME}. Kiểm tra /tmp/n8n_change_domain_stop.log. Tiếp tục với rủi ro.${NC}"
    fi
    stop_spinner; start_spinner "Tiếp tục thay đổi tên miền..."

    local old_nginx_conf_avail="/etc/nginx/sites-available/${old_domain_name}.conf"
    local old_nginx_conf_enabled="/etc/nginx/sites-enabled/${old_domain_name}.conf"
    if [ -f "$old_nginx_conf_avail" ] || [ -L "$old_nginx_conf_enabled" ]; then
        stop_spinner; start_spinner "Xóa cấu hình Nginx cũ..."
        sudo rm -f "$old_nginx_conf_avail"
        sudo rm -f "$old_nginx_conf_enabled"
        stop_spinner; start_spinner "Tiếp tục thay đổi tên miền..."
    fi

    if sudo certbot certificates -d "${old_domain_name}" 2>/dev/null | grep -q "Certificate Name:"; then
        local old_cert_name
        old_cert_name=$(sudo certbot certificates -d "${old_domain_name}" 2>/dev/null | grep "Certificate Name:" | head -n 1 | awk '{print $3}')
        if [[ -n "$old_cert_name" ]]; then
            stop_spinner; start_spinner "Xóa chứng chỉ SSL cũ (${old_cert_name})..."
            if ! sudo certbot delete --cert-name "${old_cert_name}" --non-interactive > /tmp/n8n_change_domain_cert_delete.log 2>&1; then
                 echo -e "\n${YELLOW}Cảnh báo: Không thể xóa chứng chỉ SSL cũ. Kiểm tra /tmp/n8n_change_domain_cert_delete.log.${NC}"
            fi
            stop_spinner; start_spinner "Tiếp tục thay đổi tên miền..."
        fi
    fi

    stop_spinner
    if ! create_docker_compose_config; then return 1; fi
    if ! configure_nginx_and_ssl; then return 1; fi

    start_spinner "Khởi động lại các service Docker..."
    cd "${N8N_DIR}" || { return 1; }
    if ! sudo $DOCKER_COMPOSE_CMD up -d --force-recreate > /tmp/n8n_change_domain_docker_up.log 2>&1; then
        return 1
    fi
    cd - > /dev/null
    stop_spinner

    echo -e "\n${GREEN}Thay đổi tên miền thành công!${NC}"
    echo -e "N8N hiện có thể truy cập tại: ${GREEN}https://${new_domain_for_change}${NC}"

    trap - ERR SIGINT SIGTERM
    echo -e "${YELLOW}Nhấn Enter để quay lại menu chính...${NC}"
    read -r
}

# ---- src/lib/features/upgrade.sh ----
# --- Hàm Nâng cấp phiên bản N8N ---
upgrade_n8n_version() {
    check_root
    echo -e "\n${CYAN}--- Nâng Cấp Phiên Bản N8N ---${NC}"

    if [[ ! -f "${ENV_FILE}" || ! -f "${DOCKER_COMPOSE_FILE}" ]]; then
        echo -e "${RED}Lỗi: Không tìm thấy file cấu hình ${ENV_FILE} hoặc ${DOCKER_COMPOSE_FILE}.${NC}"
        echo -e "${YELLOW}Có vẻ như N8N chưa được cài đặt. Vui lòng cài đặt trước.${NC}"
        read -r -p "Nhấn Enter để quay lại menu..."
        return 0
    fi

    local current_image_tag="latest"
    if [ -f "${DOCKER_COMPOSE_FILE}" ]; then
        current_image_tag=$(awk '/services:/ {in_services=1} /^  [^ ]/ {if(in_services) in_n8n_service=0} /'${N8N_SERVICE_NAME}':/ {if(in_services) in_n8n_service=1} /image: n8nio\/n8n:/ {if(in_n8n_service) {gsub("n8nio/n8n:", ""); print $2; exit}}' "${DOCKER_COMPOSE_FILE}")
        if [[ -z "$current_image_tag" ]]; then
            current_image_tag="latest (không xác định)"
        fi
    fi
    echo -e "Phiên bản N8N hiện tại (theo tag image): ${GREEN}${current_image_tag}${NC}"
    echo -e "${YELLOW}Chức năng này sẽ nâng cấp N8N lên phiên bản '${GREEN}latest${YELLOW}' mới nhất từ Docker Hub.${NC}"

    local confirmation_prompt
    confirmation_prompt=$(echo -e "Bạn có chắc chắn muốn tiếp tục nâng cấp không?\nNhập '${GREEN}ok${NC}' để xác nhận, hoặc bất kỳ phím nào khác để huỷ bỏ: ")
    local confirmation
    read -r -p "$confirmation_prompt" confirmation

    if [[ "$confirmation" != "ok" ]]; then
        echo -e "\n${GREEN}Huỷ bỏ nâng cấp phiên bản.${NC}"
        read -r -p "Nhấn Enter để quay lại menu..."
        return 0
    fi

    trap 'RC=$?; stop_spinner; if [[ $RC -ne 0 && $RC -ne 130 ]]; then echo -e "\n${RED}Đã xảy ra lỗi trong quá trình nâng cấp (Mã lỗi: $RC).${NC}"; fi; read -r -p "Nhấn Enter để quay lại menu..."; return 0;' ERR SIGINT SIGTERM

    start_spinner "Đang nâng cấp N8N lên phiên bản mới nhất..."

    cd "${N8N_DIR}" || { return 1; }

    stop_spinner; start_spinner "Đảm bảo cấu hình Docker Compose sử dụng tag :latest..."
    if ! create_docker_compose_config; then return 1; fi
    stop_spinner; start_spinner "Tiếp tục nâng cấp..."

    run_silent_command "Tải image N8N mới nhất (service ${N8N_SERVICE_NAME})" "$DOCKER_COMPOSE_CMD pull ${N8N_SERVICE_NAME}" "false"
    if [ $? -ne 0 ]; then cd - > /dev/null; return 1; fi

    run_silent_command "Khởi động lại N8N với phiên bản mới (service ${N8N_SERVICE_NAME})" "$DOCKER_COMPOSE_CMD up -d --force-recreate ${N8N_SERVICE_NAME}" "false"
    if [ $? -ne 0 ]; then cd - > /dev/null; return 1; fi

    cd - > /dev/null
    stop_spinner

    echo -e "\n${GREEN}Nâng cấp N8N hoàn tất! - HQ${NC}"
    echo -e "${YELLOW}N8N đã được cập nhật lên phiên bản '${GREEN}latest${YELLOW}' mới nhất.${NC}"
    echo -e "Vui lòng kiểm tra giao diện web của N8N để xác nhận phiên bản."

    trap - ERR SIGINT SIGTERM
    echo -e "${YELLOW}Nhấn Enter để quay lại menu chính...${NC}"
    read -r
}

# ---- src/lib/features/auth.sh ----
# --- Hàm Tắt Xác thực 2 bước (2FA/MFA) ---
disable_mfa() {
    check_root
    echo -e "\n${CYAN}--- Tắt Xác Thực 2 Bước (2FA/MFA) cho User N8N ---${NC}"

    if [[ ! -f "${ENV_FILE}" || ! -f "${DOCKER_COMPOSE_FILE}" ]]; then
        echo -e "${RED}Lỗi: Không tìm thấy file cấu hình ${ENV_FILE} hoặc ${DOCKER_COMPOSE_FILE}.${NC}"
        echo -e "${YELLOW}Có vẻ như N8N chưa được cài đặt. Vui lòng cài đặt trước.${NC}"
        read -r -p "Nhấn Enter để quay lại menu..."
        return 0
    fi

    local user_email
    if [[ "$NON_INTERACTIVE" == "true" && -n "$CLI_EMAIL" ]]; then
        user_email="$CLI_EMAIL"
    else
        echo -n -e "Nhập địa chỉ email của tài khoản N8N cần tắt 2FA: "
        read -r user_email

        if [[ -z "$user_email" ]]; then
            echo -e "${RED}Email không được để trống. Huỷ bỏ thao tác.${NC}"
            read -r -p "Nhấn Enter để quay lại menu..."
            return 0
        fi
    fi

    if [[ "$NON_INTERACTIVE" != "true" ]]; then
        echo -e "\n${YELLOW}Bạn có chắc chắn muốn tắt 2FA cho tài khoản với email ${GREEN}${user_email}${NC} không?${NC}"
        local confirmation_prompt
        confirmation_prompt=$(echo -e "Nhập '${GREEN}ok${NC}' để xác nhận, hoặc bất kỳ phím nào khác để huỷ bỏ: ")
        local confirmation
        read -r -p "$confirmation_prompt" confirmation

        if [[ "$confirmation" != "ok" ]]; then
            echo -e "\n${GREEN}Huỷ bỏ thao tác tắt 2FA.${NC}"
            read -r -p "Nhấn Enter để quay lại menu..."
            return 0
        fi
    fi

    trap 'RC=$?; stop_spinner; if [[ $RC -ne 0 && $RC -ne 130 ]]; then echo -e "\n${RED}Đã xảy ra lỗi (Mã lỗi: $RC).${NC}"; fi; read -r -p "Nhấn Enter để quay lại menu..."; return 0;' ERR SIGINT SIGTERM

    start_spinner "Đang tắt 2FA cho user ${user_email}..."

    local disable_mfa_log="/tmp/n8n_disable_mfa.log"
    local cli_command="docker exec -u node ${N8N_CONTAINER_NAME} n8n umfa:disable --email \"${user_email}\""

    if sudo bash -c "${cli_command}" > "${disable_mfa_log}" 2>&1; then
        stop_spinner
        echo -e "\n${GREEN}Lệnh tắt 2FA đã được thực thi.${NC}"
        cat "${disable_mfa_log}"
        if grep -q -i "disabled MFA for user with email" "${disable_mfa_log}"; then
            echo -e "${GREEN}2FA đã được tắt thành công cho user ${user_email}.${NC}"
        elif grep -q -i "does not exist" "${disable_mfa_log}"; then
            echo -e "${RED}Lỗi: Không tìm thấy user với email ${user_email}.${NC}"
        elif grep -q -i "MFA is not enabled" "${disable_mfa_log}"; then
            echo -e "${YELLOW}Thông báo: 2FA chưa được kích hoạt cho user ${user_email}.${NC}"
        else
            echo -e "${YELLOW}Vui lòng kiểm tra output ở trên để biết kết quả chi tiết.${NC}"
        fi
    else
        stop_spinner
        echo -e "\n${RED}Lỗi khi thực thi lệnh tắt 2FA.${NC}"
        cat "${disable_mfa_log}"
        echo -e "${YELLOW}Kiểm tra log Docker của container ${N8N_CONTAINER_NAME} để biết thêm chi tiết.${NC}"
    fi
    sudo rm -f "${disable_mfa_log}"

    trap - ERR SIGINT SIGTERM
    if [[ "$NON_INTERACTIVE" != "true" ]]; then
        echo -e "\n${YELLOW}Nhấn Enter để quay lại menu chính...${NC}"
        read -r
    fi
}

# --- Hàm Đặt lại thông tin đăng nhập ---
reset_user_login() {
    check_root
    echo -e "\n${CYAN}--- Đặt Lại Thông Tin Đăng Nhập User Owner N8N ---${NC}"

    if [[ ! -f "${ENV_FILE}" || ! -f "${DOCKER_COMPOSE_FILE}" ]]; then
        echo -e "${RED}Lỗi: Không tìm thấy file cấu hình ${ENV_FILE} hoặc ${DOCKER_COMPOSE_FILE}.${NC}"
        echo -e "${YELLOW}Có vẻ như N8N chưa được cài đặt. Vui lòng cài đặt trước.${NC}"
        read -r -p "Nhấn Enter để quay lại menu..."
        return 0
    fi

    if [[ "$NON_INTERACTIVE" != "true" ]]; then
        echo -e "\n${YELLOW}CẢNH BÁO: Hành động này sẽ reset toàn bộ thông tin tài khoản owner (người dùng chủ sở hữu).${NC}"
        echo -e "${YELLOW}Sau khi reset, bạn sẽ cần phải tạo lại tài khoản owner khi truy cập N8N lần đầu.${NC}"
        local confirmation_prompt
        confirmation_prompt=$(echo -e "Bạn có chắc chắn muốn tiếp tục?\nNhập '${GREEN}ok${NC}' để xác nhận, hoặc bất kỳ phím nào khác để huỷ bỏ: ")
        local confirmation
        read -r -p "$confirmation_prompt" confirmation

        if [[ "$confirmation" != "ok" ]]; then
            echo -e "\n${GREEN}Huỷ bỏ thao tác đặt lại thông tin đăng nhập.${NC}"
            read -r -p "Nhấn Enter để quay lại menu..."
            return 0
        fi
    fi

    trap 'RC=$?; stop_spinner; if [[ $RC -ne 0 && $RC -ne 130 ]]; then echo -e "\n${RED}Đã xảy ra lỗi (Mã lỗi: $RC).${NC}"; fi; read -r -p "Nhấn Enter để quay lại menu..."; return 0;' ERR SIGINT SIGTERM

    start_spinner "Đang reset thông tin đăng nhập owner..."

    local reset_log="/tmp/n8n_reset_owner.log"
    local cli_command="docker exec -u node ${N8N_CONTAINER_NAME} n8n user-management:reset"

    local cli_exit_code=0
    sudo bash -c "${cli_command}" > "${reset_log}" 2>&1 || cli_exit_code=$?

    stop_spinner

    if [[ $cli_exit_code -eq 0 ]]; then
        echo -e "\n${GREEN}Lệnh reset thông tin owner đã được thực thi.${NC}"
        echo -e "${CYAN}Output từ lệnh:${NC}"
        cat "${reset_log}"

        if grep -q -i "User data for instance owner has been reset" "${reset_log}"; then
             echo -e "${GREEN}Thông tin tài khoản owner đã được reset thành công.${NC}"
             echo -e "${YELLOW}Lần truy cập N8N tiếp theo, bạn sẽ được yêu cầu tạo lại tài khoản owner.${NC}"

             start_spinner "Đang khởi động lại N8N service..."
             cd "${N8N_DIR}" || { stop_spinner; echo -e "${RED}Không thể truy cập ${N8N_DIR}.${NC}"; return 1; }
             if ! sudo $DOCKER_COMPOSE_CMD restart ${N8N_SERVICE_NAME} > /tmp/n8n_restart_after_reset.log 2>&1; then
                 stop_spinner
                 echo -e "${RED}Lỗi khi khởi động lại N8N service. Kiểm tra /tmp/n8n_restart_after_reset.log${NC}"
             else
                 stop_spinner
                 echo -e "${GREEN}N8N service đã được khởi động lại.${NC}"
             fi
             cd - > /dev/null
        else
            echo -e "${YELLOW}Reset có thể không thành công. Vui lòng kiểm tra output ở trên.${NC}"
        fi
    else
        echo -e "\n${RED}Lỗi khi thực thi lệnh reset thông tin owner.${NC}"
        echo -e "${YELLOW}Output từ lệnh (nếu có):${NC}"
        cat "${reset_log}"
        echo -e "${YELLOW}Kiểm tra log Docker của container ${N8N_CONTAINER_NAME} để biết thêm chi tiết.${NC}"
    fi
    sudo rm -f "${reset_log}"

    trap - ERR SIGINT SIGTERM
    if [[ "$NON_INTERACTIVE" != "true" ]]; then
        echo -e "\n${YELLOW}Nhấn Enter để quay lại menu chính...${NC}"
        read -r
    fi
}

# ---- src/lib/features/data.sh ----
# --- Hàm Export Dữ Liệu ---
export_all_data() {
    check_root
    echo -e "\n${CYAN}--- Export Dữ Liệu N8N (Workflows & Credentials) ---${NC}"

    if [[ ! -f "${ENV_FILE}" || ! -f "${DOCKER_COMPOSE_FILE}" ]]; then
        echo -e "${RED}Lỗi: Không tìm thấy file cấu hình ${ENV_FILE} hoặc ${DOCKER_COMPOSE_FILE}.${NC}"
        echo -e "${YELLOW}Có vẻ như N8N chưa được cài đặt. Vui lòng cài đặt trước.${NC}"
        read -r -p "Nhấn Enter để quay lại menu..."
        return 0
    fi

    local domain_name
    domain_name=$(grep "^DOMAIN_NAME=" "${ENV_FILE}" | cut -d'=' -f2)
    if [[ -z "$domain_name" ]]; then
        echo -e "${RED}Lỗi: Không tìm thấy DOMAIN_NAME trong file ${ENV_FILE}.${NC}"
        if [[ "$NON_INTERACTIVE" != "true" ]]; then
            read -r -p "Nhấn Enter để quay lại menu..."
        fi
        return 0
    fi

    local backup_base_dir="${CLI_PATH:-${N8N_DIR}/backups}"
    local timestamp
    timestamp=$(date +"%Y%m%d_%H%M%S")
    local current_backup_dir="${backup_base_dir}/n8n_backup_${timestamp}"
    local container_temp_export_dir="/home/node/.n8n/temp_export_$$"
    local creds_file="credentials.json"
    local workflows_file="workflows.json"
    local temp_nginx_include_file_path_for_trap=""

    trap 'RC=$?; stop_spinner; \
        echo -e "\n${YELLOW}Huỷ bỏ/Lỗi trong quá trình export (Mã lỗi: $RC). Đang dọn dẹp...${NC}"; \
        sudo docker exec -u node ${N8N_CONTAINER_NAME} rm -rf "${container_temp_export_dir}" &>/dev/null; \
        if [ -n "${temp_nginx_include_file_path_for_trap}" ] && [ -f "${temp_nginx_include_file_path_for_trap}" ]; then \
            sudo rm -f "${temp_nginx_include_file_path_for_trap}"; \
            if sudo nginx -t &>/dev/null; then sudo systemctl reload nginx &>/dev/null; fi; \
            echo -e "${YELLOW}Đường dẫn tải xuống tạm thời đã được gỡ bỏ.${NC}"; \
        fi; \
        if [[ "$NON_INTERACTIVE" != "true" ]]; then read -r -p "Nhấn Enter để quay lại menu..."; fi; \
        return 0;' ERR SIGINT SIGTERM

    start_spinner "Chuẩn bị export dữ liệu..."

    if ! sudo mkdir -p "${current_backup_dir}"; then
        stop_spinner
        echo -e "${RED}Lỗi: Không thể tạo thư mục backup ${current_backup_dir}.${NC}"
        return 1
    fi
    sudo chmod 755 "${current_backup_dir}"

    if ! sudo docker exec -u node "${N8N_CONTAINER_NAME}" mkdir -p "${container_temp_export_dir}"; then
        stop_spinner
        echo -e "${RED}Lỗi: Không thể tạo thư mục tạm trong container N8N.${NC}"
        return 1
    fi
    stop_spinner

    # Export credentials
    local export_creds_log="/tmp/n8n_export_creds.log"
    local export_creds_cmd="n8n export:credentials --all --output=${container_temp_export_dir}/${creds_file}"
    local export_creds_success=false

    start_spinner "Đang export credentials..."
    if sudo docker exec -u node "${N8N_CONTAINER_NAME}" ${export_creds_cmd} > "${export_creds_log}" 2>&1; then
        if sudo docker cp "${N8N_CONTAINER_NAME}:${container_temp_export_dir}/${creds_file}" "${current_backup_dir}/${creds_file}"; then
            export_creds_success=true
            echo -e "\r\033[K${GREEN}Export credentials thành công.${NC}"
        else
            echo -e "\r\033[K${RED}Lỗi khi sao chép ${creds_file} từ container.${NC}"
        fi
    else
        if grep -q -i "No credentials found" "${export_creds_log}" || \
           grep -q -i "No items to export" "${export_creds_log}"; then
            echo -e "\r\033[K${YELLOW}Không tìm thấy credentials để export. Tạo file rỗng...${NC}"
            echo "{}" | sudo tee "${current_backup_dir}/${creds_file}" > /dev/null
            export_creds_success=true
        else
            echo -e "\r\033[K${RED}Lỗi khi export credentials.${NC}"
            echo -e "${YELLOW}Output từ lệnh:${NC}"
            cat "${export_creds_log}"
        fi
    fi
    stop_spinner
    sudo rm -f "${export_creds_log}"
    if [[ "$export_creds_success" != true ]]; then return 1; fi

    # Export workflows
    local export_workflows_log="/tmp/n8n_export_workflows.log"
    local export_workflows_cmd="n8n export:workflow --all --output=${container_temp_export_dir}/${workflows_file}"
    local export_workflows_success=false

    start_spinner "Đang export workflows..."
    if sudo docker exec -u node "${N8N_CONTAINER_NAME}" ${export_workflows_cmd} > "${export_workflows_log}" 2>&1; then
        if sudo docker cp "${N8N_CONTAINER_NAME}:${container_temp_export_dir}/${workflows_file}" "${current_backup_dir}/${workflows_file}"; then
            export_workflows_success=true
            echo -e "\r\033[K${GREEN}Export workflows thành công.${NC}"
        else
            echo -e "\r\033[K${RED}Lỗi khi sao chép ${workflows_file} từ container.${NC}"
        fi
    else
        if grep -q -i "No workflows found" "${export_workflows_log}" || \
           grep -q -i "No items to export" "${export_workflows_log}"; then
            echo -e "\r\033[K${YELLOW}Không tìm thấy workflows để export. Tạo file rỗng...${NC}"
            echo "[]" | sudo tee "${current_backup_dir}/${workflows_file}" > /dev/null
            export_workflows_success=true
        else
            echo -e "\r\033[K${RED}Lỗi khi export workflows.${NC}"
            echo -e "${YELLOW}Output từ lệnh:${NC}"
            cat "${export_workflows_log}"
        fi
    fi
    stop_spinner
    sudo rm -f "${export_workflows_log}"
    if [[ "$export_workflows_success" != true ]]; then return 1; fi

    echo -e "Đường dẫn lưu trữ trên server: ${YELLOW}${current_backup_dir}${NC}"

    start_spinner "Dọn dẹp thư mục tạm trong container..."
    sudo docker exec -u node "${N8N_CONTAINER_NAME}" rm -rf "${container_temp_export_dir}" &>/dev/null
    stop_spinner

    # Tạo đường dẫn tải xuống tạm thời qua Nginx
    local random_signature
    random_signature=$(generate_random_string 16)
    sudo mkdir -p "${NGINX_EXPORT_INCLUDE_DIR}"
    local temp_nginx_include_file="${NGINX_EXPORT_INCLUDE_DIR}/${NGINX_EXPORT_INCLUDE_FILE_BASENAME}_${random_signature}.conf"
    temp_nginx_include_file_path_for_trap="${temp_nginx_include_file}"
    local download_path_segment="n8n-backup-${random_signature}"

    start_spinner "Tạo đường dẫn tải xuống tạm thời..."

    local nginx_export_content
    nginx_export_content=$(cat <<EOF
location /${download_path_segment}/ {
    alias ${current_backup_dir}/;
    add_header Content-Disposition "attachment";
    autoindex off;
    expires off;
}
EOF
)
    echo "$nginx_export_content" | sudo tee "${temp_nginx_include_file}" > /dev/null
    if [ $? -ne 0 ]; then
        stop_spinner
        echo -e "${RED}Lỗi khi tạo file cấu hình Nginx tạm thời: ${temp_nginx_include_file}.${NC}"
        temp_nginx_include_file_path_for_trap=""
        return 1
    fi

    if ! sudo nginx -t > /tmp/nginx_export_test.log 2>&1; then
        stop_spinner
        echo -e "${RED}Lỗi cấu hình Nginx. Kiểm tra /tmp/nginx_export_test.log.${NC}"
        sudo rm -f "${temp_nginx_include_file}"
        temp_nginx_include_file_path_for_trap=""
        return 1
    fi
    sudo systemctl reload nginx
    stop_spinner
    echo -e "${GREEN}Đường dẫn tải xuống tạm thời đã được tạo.${NC}"

    if [[ "$NON_INTERACTIVE" != "true" ]]; then
        echo -e "\n${YELLOW}--- HƯỚNG DẪN TẢI XUỐNG ---${NC}"
        echo -e "Các file backup đã được export thành công."
        echo -e "Bạn có thể tải xuống qua các đường dẫn sau (chỉ có hiệu lực trong phiên này):"
        echo -e "  Credentials: ${GREEN}https://${domain_name}/${download_path_segment}/${creds_file}${NC}"
        echo -e "  Workflows:   ${GREEN}https://${domain_name}/${download_path_segment}/${workflows_file}${NC}"
        echo -e "\n${RED}QUAN TRỌNG:${NC} Sau khi bạn tải xong, nhấn Enter để vô hiệu hoá các đường dẫn này."

        read -r -p "Nhấn Enter sau khi bạn đã tải xong các file..."

        start_spinner "Vô hiệu hoá đường dẫn tải xuống..."
        sudo rm -f "${temp_nginx_include_file}"
        temp_nginx_include_file_path_for_trap=""
        if ! sudo nginx -t > /tmp/nginx_export_test_remove.log 2>&1; then
            echo -e "\n${YELLOW}Cảnh báo: Có lỗi khi kiểm tra Nginx sau khi xóa file include, nhưng vẫn tiếp tục.${NC}"
        fi
        sudo systemctl reload nginx
        stop_spinner
        echo -e "${GREEN}Đường dẫn tải xuống đã được vô hiệu hoá.${NC}"
    else
        # Xóa ngay Nginx config nếu chạy qua CLI (tránh quên)
        sudo rm -f "${temp_nginx_include_file}"
        temp_nginx_include_file_path_for_trap=""
        sudo systemctl reload nginx &>/dev/null
    fi
    echo -e "Các file backup được lưu trữ tại: ${YELLOW}${current_backup_dir}${NC} trên server."

    trap - ERR SIGINT SIGTERM
    if [[ "$NON_INTERACTIVE" != "true" ]]; then
        echo -e "\n${YELLOW}Nhấn Enter để quay lại menu chính...${NC}"
        read -r
    fi
}

# --- Hàm Import Dữ Liệu ---
import_data() {
    check_root

    if [[ ! -f "${ENV_FILE}" || ! -f "${DOCKER_COMPOSE_FILE}" ]]; then
        echo -e "${RED}Lỗi: Không tìm thấy file cấu hình ${ENV_FILE} hoặc ${DOCKER_COMPOSE_FILE}.${NC}"
        echo -e "${YELLOW}Có vẻ như N8N chưa được cài đặt. Vui lòng cài đặt trước.${NC}"
        if [[ "$NON_INTERACTIVE" != "true" ]]; then read -r -p "Nhấn Enter để quay lại menu..."; fi
        return 0
    fi

    local template_file_full_path="${CLI_FILE:-${TEMPLATE_DIR}/${TEMPLATE_FILE_NAME}}"

    if [ ! -f "$template_file_full_path" ]; then
        echo -e "${RED}Lỗi: File data '${template_file_full_path}' không tìm thấy trên server.${NC}"
        echo -e "${YELLOW}Vui lòng cấp đúng đường dẫn file JSON có đuôi .json.${NC}"
        if [[ "$NON_INTERACTIVE" != "true" ]]; then read -r -p "Nhấn Enter để quay lại menu..."; fi
        return 0
    fi

    trap 'RC=$?; stop_spinner; \
        echo -e "\n${YELLOW}Huỷ bỏ/Lỗi trong quá trình import (Mã lỗi: $RC). Đang dọn dẹp...${NC}"; \
        sudo docker exec -u node ${N8N_CONTAINER_NAME} rm -rf "/home/node/.n8n/temp_import_template_$$" &>/dev/null; \
        if [[ "$NON_INTERACTIVE" != "true" ]]; then read -r -p "Nhấn Enter để quay lại menu..."; fi; \
        return 0;' ERR SIGINT SIGTERM

    local container_temp_import_dir="/home/node/.n8n/temp_import_template_$$"

    start_spinner "Chuẩn bị import workflow từ template..."
    if ! sudo docker exec -u node "${N8N_CONTAINER_NAME}" mkdir -p "${container_temp_import_dir}"; then
        stop_spinner
        echo -e "${RED}Lỗi: Không thể tạo thư mục tạm trong container N8N.${NC}"
        return 1
    fi

    local target_file_name
    target_file_name=$(basename "$template_file_full_path")
    local docker_cp_command="docker cp \"${template_file_full_path}\" \"${N8N_CONTAINER_NAME}:${container_temp_import_dir}/${target_file_name}\""
    if ! sudo bash -c "$docker_cp_command" >/dev/null 2>&1; then
        echo -e "${RED}Lỗi khi sao chép file data vào container.${NC}"
        sudo docker exec -u node "${N8N_CONTAINER_NAME}" rm -rf "${container_temp_import_dir}" &>/dev/null
        return 1
    fi

    start_spinner "Đang import dữ liệu từ file ${target_file_name}..."
    local import_cmd="n8n import:workflow --input=${container_temp_import_dir}/${target_file_name}"
    # Nếu file tên credentials thì đổi cờ
    if [[ "$target_file_name" == *"credential"* ]]; then
        import_cmd="n8n import:credentials --input=${container_temp_import_dir}/${target_file_name}"
    fi

    local import_log="/tmp/n8n_import_template.log"

    if ! sudo docker exec -u node "${N8N_CONTAINER_NAME}" ${import_cmd} > "${import_log}" 2>&1; then
        stop_spinner
        echo -e "\n${RED}Lỗi khi import dữ liệu.${NC}"
        cat "${import_log}"
    else
        stop_spinner
        echo -e "\n${GREEN}[+] Import dữ liệu thành công!${NC}"
        if [[ "$NON_INTERACTIVE" != "true" ]]; then
            echo -e "\n${YELLOW}--- HƯỚNG DẪN SỬ DỤNG ---${NC}"
            echo -e "1. Truy cập vào N8N qua trình duyệt."
            echo -e "2. Kiểm tra lại workflows và credentials mới vừa nạp vào."
            echo -e "3. Đảm bảo cấu hình lại Token & API Key cần thiết."
        fi
    fi
    sudo rm -f "${import_log}"

    start_spinner "Dọn dẹp thư mục tạm trong container..."
    sudo docker exec -u node "${N8N_CONTAINER_NAME}" rm -rf "${container_temp_import_dir}" &>/dev/null
    stop_spinner

    trap - ERR SIGINT SIGTERM
    if [[ "$NON_INTERACTIVE" != "true" ]]; then
        echo -e "\n${YELLOW}Nhấn Enter để quay lại menu chính...${NC}"
        read -r
    fi
}

# ---- src/lib/features/redis.sh ----
# --- Hàm Lấy thông tin Redis ---
get_redis_info() {
    check_root
    echo -e "\n${CYAN}--- Lấy Thông Tin Kết Nối Redis ---${NC}"

    if [ ! -f "${ENV_FILE}" ]; then
        echo -e "${RED}Lỗi: File cấu hình ${ENV_FILE} không tìm thấy.${NC}"
        echo -e "${YELLOW}Có vẻ như N8N chưa được cài đặt. Vui lòng cài đặt trước (chọn mục 1).${NC}"
        read -r -p "Nhấn Enter để quay lại menu..."
        return 0
    fi

    local redis_password
    redis_password=$(grep "^REDIS_PASSWORD=" "${ENV_FILE}" | cut -d'=' -f2)

    local server_ip
    server_ip=$(get_public_ip)

    if [[ -z "$redis_password" ]]; then
        echo -e "${RED}Lỗi: Không tìm thấy REDIS_PASSWORD trong file ${ENV_FILE}.${NC}"
        echo -e "${YELLOW}File cấu hình có thể bị lỗi hoặc Redis chưa được cấu hình đúng.${NC}"
    else
        echo -e "${GREEN}Thông tin kết nối Redis:${NC}"
        echo -e "  ${CYAN}Host:${NC}     ${server_ip}"
        echo -e "  ${CYAN}Port:${NC}     6379"
        echo -e "  ${CYAN}User:${NC}     default"
        echo -e "  ${CYAN}Password:${NC} ${YELLOW}${redis_password}${NC}"
    fi
    echo -e "\n${YELLOW}Nhấn Enter để quay lại menu chính...${NC}"
    read -r
}

# ---- src/lib/features/database.sh ----
# --- Hàm Lấy thông tin kết nối CSDL PostgreSQL ---
get_database_info() {
    check_root
    echo -e "\n${CYAN}--- Lấy Thông Tin Kết Nối PostgreSQL ---${NC}"

    if [ ! -f "${ENV_FILE}" ]; then
        echo -e "${RED}Lỗi: File cấu hình ${ENV_FILE} không tìm thấy.${NC}"
        echo -e "${YELLOW}Có vẻ như N8N chưa được cài đặt. Vui lòng cài đặt trước (chọn mục 1).${NC}"
        read -r -p "Nhấn Enter để quay lại menu..."
        return 0
    fi

    local db_host="127.0.0.1" # Mặc định Docker chạy ở local
    local db_port="5432"
    local db_name
    db_name=$(grep "^POSTGRES_DB=" "${ENV_FILE}" | cut -d'=' -f2)
    local db_user
    db_user=$(grep "^POSTGRES_USER=" "${ENV_FILE}" | cut -d'=' -f2)
    local db_password
    db_password=$(grep "^POSTGRES_PASSWORD=" "${ENV_FILE}" | cut -d'=' -f2)

    if [[ -z "$db_name" || -z "$db_user" || -z "$db_password" ]]; then
        echo -e "${RED}Lỗi: Không tìm thấy đầy đủ thông tin kết nối Database trong file ${ENV_FILE}.${NC}"
        echo -e "${YELLOW}File cấu hình có thể bị lỗi hoặc Database chưa được cấu hình đúng.${NC}"
    else
        echo -e "${GREEN}Thông tin kết nối PostgreSQL (Mặc định chỉ được truy cập nội bộ Docker):${NC}"
        echo -e "  ${CYAN}Host:${NC}     postgres (hoặc 127.0.0.1 nếu map port)"
        echo -e "  ${CYAN}Port:${NC}     ${db_port}"
        echo -e "  ${CYAN}Database:${NC} ${db_name}"
        echo -e "  ${CYAN}User:${NC}     ${db_user}"
        echo -e "  ${CYAN}Password:${NC} ${YELLOW}${db_password}${NC}"
        echo -e "\n${YELLOW}Lưu ý: Mặc định kịch bản Dymanic Host không mở cổng 5432 ra public internet để bảo mật.${NC}"
        echo -e "${YELLOW}Bạn cần cấu hình docker-compose nếu muốn map ports 5432:5432 ra ngoài.${NC}"
    fi
    echo -e "\n${YELLOW}Nhấn Enter để quay lại menu chính...${NC}"
    read -r
}

# ---- src/lib/features/service.sh ----
# --- Quản lý Dịch vụ (Service Control) ---

# Xem trạng thái các container N8N và Redis
show_status() {
  clear
  echo -e "${CYAN}=== TRẠNG THÁI DỊCH VỤ ===${NC}"
  if [ ! -d "$N8N_DIR" ]; then
    echo -e "${RED}[!] Thư mục cài đặt ${N8N_DIR} không tồn tại. Vui lòng cài đặt N8N trước.${NC}"
    read -n 1 -s -r -p "Nhấn phím bất kỳ để quay lại menu..."
    return 1
  fi

  cd "$N8N_DIR" || return 1
  echo -e "${YELLOW}Đang lấy trạng thái từ Docker Compose...${NC}"
  echo "------------------------------------------------------------------------------------"
  $DOCKER_COMPOSE_CMD ps
  echo "------------------------------------------------------------------------------------"
  
  # Hiển thị mức sử dụng tài nguyên nhanh
  echo -e "\n${YELLOW}Tài nguyên sử dụng (CPU/RAM):${NC}"
  docker stats --no-stream --format "table {{.Name}}\t{{.CPUPerc}}\t{{.MemUsage}}\t{{.NetIO}}" | grep -E "Name|${N8N_CONTAINER_NAME}|n8n_redis|n8n_postgres|redis|postgres" || echo "Không có container nào đang chạy."
  
  echo ""
  read -n 1 -s -r -p "Nhấn phím bất kỳ để quay lại menu..."
}

# Khởi động lại N8N và Redis
restart_services() {
  clear
  echo -e "${CYAN}=== KHỞI ĐỘNG LẠI DỊCH VỤ ===${NC}"
  if [ ! -d "$N8N_DIR" ]; then
    echo -e "${RED}[!] Thư mục cài đặt ${N8N_DIR} không tồn tại.${NC}"
    sleep 2
    return 1
  fi

  cd "$N8N_DIR" || return 1
  echo -e "${YELLOW}[!] Lệnh này sẽ khởi động lại N8N và Redis. Sẽ mất một chút thời gian.${NC}"
  read -p "Bạn có chắc chắn muốn khởi động lại hệ thống? (y/n): " confirm
  if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then
    echo "Đã hủy thao tác."
    sleep 1
    return 0
  fi

  # Restart N8N and Redis
  run_silent_command "Đang khởi động lại Docker Compose services" "cd $N8N_DIR && $DOCKER_COMPOSE_CMD restart" false
  
  if [ $? -eq 0 ]; then
    echo -e "${GREEN}[+] Hệ thống đã được khởi động lại thành công!${NC}"
    echo -e "${YELLOW}[*] Lưu ý: Có thể mất 1-2 phút để N8N khởi động lên hoàn toàn.${NC}"
  fi
  sleep 3
}

# Xem logs của N8N
view_logs() {
  clear
  echo -e "${CYAN}=== XEM LOGS N8N ===${NC}"
  if [ ! -d "$N8N_DIR" ]; then
    echo -e "${RED}[!] Thư mục cài đặt ${N8N_DIR} không tồn tại.${NC}"
    sleep 2
    return 1
  fi

  cd "$N8N_DIR" || return 1
  echo -e "${YELLOW}[*] Đang hiển thị 100 dòng log gần nhất của N8N.${NC}"
  echo -e "${YELLOW}[*] Ấn Ctrl+C để thoát khỏi màn hình xem log.${NC}"
  echo "------------------------------------------------------------------------------------"
  
  $DOCKER_COMPOSE_CMD logs -f --tail=100 $N8N_SERVICE_NAME
  
  echo "------------------------------------------------------------------------------------"
  read -n 1 -s -r -p "Nhấn phím bất kỳ để quay lại menu..."
}

# ---- src/lib/features/cleanup.sh ----
# --- Dọn dẹp Hệ thống (System Cleanup) ---

# Dọn dẹp rác Docker
docker_prune() {
  clear
  echo -e "${CYAN}=== DỌN DẸP HỆ THỐNG (DOCKER) ===${NC}"
  echo -e "${YELLOW}[!] Tính năng này sẽ dọn dẹp không gian ổ đĩa bằng cách xóa:${NC}"
  echo "- Tất cả Docker container đã dừng lại."
  echo "- Tất cả Networks không được sử dụng bởi ít nhất 1 container."
  echo "- Tất cả Docker Images lủng lẳng (dangling) không có thẻ tên."
  echo "- Tất cả Build Cache không được sử dụng."
  echo ""
  echo -e "${RED}Lưu ý: Dữ liệu N8N của bạn sẽ không bị ảnh hưởng (vì chúng nằm trong Volume).${NC}"
  echo ""
  
  if [[ "$NON_INTERACTIVE" != "true" ]]; then
    read -p "Bạn có muốn tiếp tục dọn dẹp hệ thống không? (y/n): " confirm
    if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then
      echo "Đã hủy thao tác."
      sleep 1
      return 0
    fi
  fi

  # Chạy lệnh
  run_silent_command "Đang dọn dẹp Docker system" "docker system prune -a -f --volumes" false
  
  if [ $? -eq 0 ]; then
    echo -e "${GREEN}[+] Đã dọn dẹp hệ thống thành công!${NC}"
    
    # Check current disk space
    echo -e "\n${YELLOW}Tình trạng ổ cứng hiện tại:${NC}"
    df -h / | tail -n 1 | awk '{print "Tổng: " $2 "\nĐã dùng: " $3 " (" $5 ")\nCòn trống: " $4}'
  fi
  
  if [[ "$NON_INTERACTIVE" != "true" ]]; then
    echo ""
    read -n 1 -s -r -p "Nhấn phím bất kỳ để quay lại menu..."
  fi
}

# ---- src/lib/features/backup.sh ----
# --- Sao lưu & Phục hồi Toàn Hệ thống ---
BACKUP_DIR="${N8N_DIR}/backups"

# Tạo bản sao lưu (Backup)
backup_server() {
  clear
  echo -e "${CYAN}=== BACKUP TOÀN BỘ HỆ THỐNG N8N ===${NC}"
  if [ ! -d "$N8N_DIR" ]; then
    echo -e "${RED}[!] Thư mục cài đặt ${N8N_DIR} không tồn tại.${NC}"
    read -n 1 -s -r -p "Nhấn phím bất kỳ để quay lại menu..."
    return 1
  fi
  
  # Tạo thư mục gốc cho Backup nếu chưa có
  mkdir -p "$BACKUP_DIR"
  
  local timestamp=$(date +%Y%m%d_%H%M%S)
  local current_backup_dir="${BACKUP_DIR}/n8n_backup_${timestamp}"
  
  echo -e "${YELLOW}[*] Hệ thống sẽ tạo một bản nén đầy đủ bao gồm:${NC}"
  echo "- Cấu hình Docker & Môi trường (.env)"
  echo "- Dữ liệu Workflows & Credentials"
  echo "- Dữ liệu Database PostgreSQL"
  echo "- Thư mục cấu hình N8N"
  echo ""
  
  if [[ "$NON_INTERACTIVE" != "true" ]]; then
    read -p "Bạn có muốn tiếp tục Backup không? (y/n): " confirm
    if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then
      echo "Đã hủy thao tác."
      sleep 1
      return 0
    fi
  fi

  local temp_nginx_include_file_path_for_trap=""
  trap 'RC=$?; stop_spinner; \
      echo -e "\n${YELLOW}Huỷ bỏ/Lỗi trong quá trình Backup (Mã lỗi: $RC). Đang dọn dẹp...${NC}"; \
      if [ -n "${temp_nginx_include_file_path_for_trap}" ] && [ -f "${temp_nginx_include_file_path_for_trap}" ]; then \
          sudo rm -f "${temp_nginx_include_file_path_for_trap}"; \
          if sudo nginx -t &>/dev/null; then sudo systemctl reload nginx &>/dev/null; fi; \
          echo -e "${YELLOW}Đường dẫn tải xuống tạm thời đã được gỡ bỏ.${NC}"; \
      fi; \
      read -r -p "Nhấn Enter để quay lại menu..."; \
      return 0;' ERR SIGINT SIGTERM

  sudo mkdir -p "${current_backup_dir}"
  
  # 1. Export Credentials & Workflows (thông qua container n8n)
  start_spinner "Đang trích xuất Workflows & Credentials..."
  local container_temp_export_dir="/home/node/.n8n/temp_export_$$"
  sudo docker exec -u node "${N8N_CONTAINER_NAME}" mkdir -p "${container_temp_export_dir}"
  sudo docker exec -u node "${N8N_CONTAINER_NAME}" n8n export:credentials --all --output="${container_temp_export_dir}/credentials.json" &>/dev/null
  sudo docker exec -u node "${N8N_CONTAINER_NAME}" n8n export:workflow --all --output="${container_temp_export_dir}/workflows.json" &>/dev/null
  sudo docker cp "${N8N_CONTAINER_NAME}:${container_temp_export_dir}/credentials.json" "${current_backup_dir}/credentials.json" &>/dev/null
  sudo docker cp "${N8N_CONTAINER_NAME}:${container_temp_export_dir}/workflows.json" "${current_backup_dir}/workflows.json" &>/dev/null
  sudo docker exec -u node "${N8N_CONTAINER_NAME}" rm -rf "${container_temp_export_dir}" &>/dev/null
  stop_spinner

  # 2. Export Database PostgreSQL
  start_spinner "Đang trích xuất Cơ sở dữ liệu PostgreSQL..."
  local db_user=$(grep "^POSTGRES_USER=" "${ENV_FILE}" | cut -d'=' -f2)
  local db_name=$(grep "^POSTGRES_DB=" "${ENV_FILE}" | cut -d'=' -f2)
  if [[ -n "$db_user" && -n "$db_name" ]]; then
      sudo docker exec n8n_postgres pg_dump -U "$db_user" -d "$db_name" -F c -f "/tmp/database.dump" &>/dev/null
      sudo docker cp "n8n_postgres:/tmp/database.dump" "${current_backup_dir}/database.dump" &>/dev/null
      sudo docker exec n8n_postgres rm -f "/tmp/database.dump" &>/dev/null
  fi
  stop_spinner

  # 3. Copy các file cấu hình quan trọng
  start_spinner "Đang sao lưu cấu hình môi trường..."
  sudo cp "${N8N_DIR}/.env" "${current_backup_dir}/" &>/dev/null
  sudo cp "${N8N_DIR}/docker-compose.yml" "${current_backup_dir}/" &>/dev/null
  stop_spinner
  
  # 4. Gom tất cả lại thành 1 file .tar.gz duy nhất
  local backup_filename="n8n_full_backup_${timestamp}.tar.gz"
  local final_backup_file="${BACKUP_DIR}/${backup_filename}"
  run_silent_command "Đang nén toàn bộ dữ liệu thành 1 file (tùy dung lượng sẽ tốn vài phút)" "cd ${BACKUP_DIR} && tar -czf ${final_backup_file} $(basename ${current_backup_dir})" false
  
  if [ $? -eq 0 ]; then
    # Xoá thư mục tạm sau khi nén xong
    sudo rm -rf "${current_backup_dir}"
    echo -e "${GREEN}[+] Đã sao lưu TOÀN BỘ hệ thống thành công!${NC}"
    echo -e "${YELLOW}File lưu tại: ${final_backup_file}${NC}"
    
    # Tạo đường dẫn tải xuống tạm thời qua Nginx
    local domain_name
    domain_name=$(grep "^DOMAIN_NAME=" "${ENV_FILE}" | cut -d'=' -f2)
    if [[ -n "$domain_name" ]]; then
        local random_signature=$(generate_random_string 16)
        sudo mkdir -p "${NGINX_EXPORT_INCLUDE_DIR}"
        local temp_nginx_include_file="${NGINX_EXPORT_INCLUDE_DIR}/${NGINX_EXPORT_INCLUDE_FILE_BASENAME}_${random_signature}.conf"
        temp_nginx_include_file_path_for_trap="${temp_nginx_include_file}"
        local download_path_segment="n8n-backup-${random_signature}"

        start_spinner "Tạo đường dẫn tải xuống tạm thời..."
        local nginx_export_content=$(cat <<EOF
location /${download_path_segment}/ {
    alias ${BACKUP_DIR}/;
    add_header Content-Disposition "attachment";
    autoindex off;
    expires off;
}
EOF
)
        echo "$nginx_export_content" | sudo tee "${temp_nginx_include_file}" > /dev/null
        if sudo nginx -t > /tmp/nginx_export_test.log 2>&1; then
            sudo systemctl reload nginx
            stop_spinner
            echo -e "\n${YELLOW}--- HƯỚNG DẪN TẢI XUỐNG ---${NC}"
            echo -e "Bạn có thể tải xuống file Backup qua đường dẫn sau (chỉ có hiệu lực trong phiên này):"
            echo -e "  Link tải: ${GREEN}https://${domain_name}/${download_path_segment}/${backup_filename}${NC}"
            echo -e "\n${RED}QUAN TRỌNG:${NC} Sau khi tải xong, nhấn Enter để vô hiệu hoá đường dẫn này."
            
            read -r -p "Nhấn Enter sau khi bạn đã tải xong..."
            
            start_spinner "Vô hiệu hoá đường dẫn tải xuống..."
            sudo rm -f "${temp_nginx_include_file}"
            temp_nginx_include_file_path_for_trap=""
            sudo systemctl reload nginx
            stop_spinner
            echo -e "${GREEN}Đường dẫn tải xuống đã được vô hiệu hoá.${NC}"
        else
            stop_spinner
            echo -e "${RED}Lỗi cấu hình Nginx. Không thể tạo link tải. Kiểm tra /tmp/nginx_export_test.log.${NC}"
            sudo rm -f "${temp_nginx_include_file}"
            temp_nginx_include_file_path_for_trap=""
            echo ""
            read -n 1 -s -r -p "Nhấn phím bất kỳ để quay lại menu..."
        fi
    else
        echo -e "${YELLOW}[*] Không thấy Domain, vui lòng dùng FTP sftp để tải file.${NC}"
        echo ""
        read -n 1 -s -r -p "Nhấn phím bất kỳ để quay lại menu..."
    fi
  else
    echo -e "${RED}[!] Quá trình nén file thất bại.${NC}"
    echo ""
  if [[ "$NON_INTERACTIVE" != "true" ]]; then
    read -n 1 -s -r -p "Nhấn phím bất kỳ để quay lại menu..."
  fi
  fi
  
  trap - ERR SIGINT SIGTERM
}

# Phục hồi (Restore)
restore_server() {
  clear
  echo -e "${CYAN}=== RESTORE HỆ THỐNG (TỪ FILE BACKUP) ===${NC}"
  
  if [ ! -d "$BACKUP_DIR" ] || [ -z "$(ls -A ${BACKUP_DIR}/*.tar.gz 2>/dev/null)" ]; then
    echo -e "${RED}[!] Không tìm thấy bất kỳ file Backup nào trong thư mục ${BACKUP_DIR}${NC}"
    echo -e "${YELLOW}[*] Xin vui lòng upload file .tar.gz vào thư mục ${BACKUP_DIR} trước, hoặc chạy lệnh Backup trước.${NC}"
    read -n 1 -s -r -p "Nhấn phím bất kỳ để quay lại menu..."
    return 1
  fi
  
  local selected_file
  if [[ "$NON_INTERACTIVE" == "true" && -n "$CLI_FILE" ]]; then
    selected_file="$CLI_FILE"
    if [ ! -f "$selected_file" ]; then
      echo -e "${RED}[!] Không tìm thấy file: $selected_file${NC}"
      return 1
    fi
  else
    echo -e "${YELLOW}[*] Danh sách các bản Backup có trên Server:${NC}"
    echo "--------------------------------------------------------"
    
    # Liệt kê file
    local files=(${BACKUP_DIR}/*.tar.gz)
    local num_files=${#files[@]}
    for ((i=0; i<num_files; i++)); do
      local size=$(du -h "${files[i]}" | cut -f1)
      local filename=$(basename "${files[i]}")
      printf " [%2d]  %-40s %s\n" "$((i+1))" "$filename" "(Size: $size)"
    done
    
    echo "--------------------------------------------------------"
    echo " [0]  Hủy bỏ và quay lại"
    echo ""
    
    read -p "Chọn số tương ứng với file bạn muốn Restore (0-${num_files}): " choice
    if ! [[ "$choice" =~ ^[0-9]+$ ]] || [ "$choice" -lt 0 ] || [ "$choice" -gt "$num_files" ]; then
       echo -e "${RED}[!] Lựa chọn không hợp lệ.${NC}"
       sleep 1
       return 1
    fi
    
    if [ "$choice" -eq 0 ]; then
      echo "Đã hủy thao tác."
      sleep 1
      return 0
    fi
    
    # Lấy tên file Restore
    selected_file=${files[$((choice-1))]}
  fi
  
  echo -e "\n${RED}[!!!] CẢNH BÁO NGUY HIỂM [!!!]${NC}"
  echo "Bạn đang yêu cầu phục hồi dữ liệu từ file: $(basename $selected_file)"
  echo "Điều này sẽ XÓA TOÀN BỘ dữ liệu hiện tại trong N8N (Database, Workflow mới) và GHI ĐÈ dữ liệu từ Backup!"
  echo ""
  
  if [[ "$NON_INTERACTIVE" != "true" ]]; then
    read -p "Bạn có CHẮC CHẮN MUỐN PHỤC HỒI hệ thống từ bản sao này không? Kể cả việc ghi đè tất cả? (Thay vì 'y', nhập chữ 'RESTORE' để đồng ý): " confirm_word
    if [[ "$confirm_word" != "RESTORE" ]]; then
      echo -e "${YELLOW}[*] Không trùng khớp (bạn không nhập từ RESTORE). Đã hủy thao tác.${NC}"
      sleep 2
      return 0
    fi
  else
    echo -e "${YELLOW}[*] Khởi chạy chế độ tự động RESTORE không cần hỏi...${NC}"
  fi
  
  # Tạo thư mục giải nén tạm thời
  local temp_extract_dir="/tmp/n8n_restore_$$"
  sudo mkdir -p "${temp_extract_dir}"
  run_silent_command "Đang giải nén file backup..." "tar -xzf ${selected_file} -C ${temp_extract_dir}" false

  # Tên folder bên trong file nén (ví dụ n8n_backup_2026...)
  local extracted_folder
  extracted_folder=$(ls -1 "${temp_extract_dir}" | head -n 1)
  local extract_source="${temp_extract_dir}/${extracted_folder}"

  # Khôi phục file cấu hình môi trường (.env, docker-compose.yml)
  start_spinner "Đang khôi phục file cấu hình..."
  if [ -f "${extract_source}/.env" ]; then
    sudo cp "${extract_source}/.env" "${N8N_DIR}/"
  fi
  if [ -f "${extract_source}/docker-compose.yml" ]; then
    sudo cp "${extract_source}/docker-compose.yml" "${N8N_DIR}/"
  fi
  stop_spinner

  # Đảm bảo các hệ thống đang chạy
  run_silent_command "Đảm bảo database đang hoạt động để restore..." "cd ${N8N_DIR} && ${DOCKER_COMPOSE_CMD} up -d postgres" false
  
  # Đợi Postgres sẵn sàng
  sleep 5
  
  # 2. Phục hồi Database PostgreSQL
  if [ -f "${extract_source}/database.dump" ]; then
    start_spinner "Đang khôi phục Cơ sở dữ liệu..."
    local db_user=$(grep "^POSTGRES_USER=" "${N8N_DIR}/.env" | cut -d'=' -f2)
    local db_name=$(grep "^POSTGRES_DB=" "${N8N_DIR}/.env" | cut -d'=' -f2)
    sudo docker cp "${extract_source}/database.dump" n8n_postgres:/tmp/database.dump
    sudo docker exec n8n_postgres pg_restore -U "$db_user" -d "$db_name" --clean --if-exists -1 "/tmp/database.dump" &>/dev/null
    sudo docker exec n8n_postgres rm -f "/tmp/database.dump" &>/dev/null
    stop_spinner
  fi

  # Bước khởi động lại toàn bộ N8N sau khi nạp cấu hình và database
  run_silent_command "Đang khởi động N8N platform..." "cd ${N8N_DIR} && ${DOCKER_COMPOSE_CMD} up -d n8n" false
  
  # Chờ N8N load hoàn chỉnh
  start_spinner "Đang chờ N8N khởi động để nạp Credentials và Workflows..."
  sleep 15
  stop_spinner

  # 3. Phục hồi Credentials & Workflows (thông qua container n8n)
  start_spinner "Đang nạp lại Workflows và Credentials..."
  local container_temp_import_dir="/home/node/.n8n/temp_import_$$"
  sudo docker exec -u node "${N8N_CONTAINER_NAME}" mkdir -p "${container_temp_import_dir}"
  
  if [ -f "${extract_source}/credentials.json" ]; then
    sudo docker cp "${extract_source}/credentials.json" "${N8N_CONTAINER_NAME}:${container_temp_import_dir}/credentials.json"
    sudo docker exec -u node "${N8N_CONTAINER_NAME}" n8n import:credentials --input="${container_temp_import_dir}/credentials.json" &>/dev/null
  fi
  
  if [ -f "${extract_source}/workflows.json" ]; then
    sudo docker cp "${extract_source}/workflows.json" "${N8N_CONTAINER_NAME}:${container_temp_import_dir}/workflows.json"
    sudo docker exec -u node "${N8N_CONTAINER_NAME}" n8n import:workflow --input="${container_temp_import_dir}/workflows.json" &>/dev/null
  fi
  
  sudo docker exec -u node "${N8N_CONTAINER_NAME}" rm -rf "${container_temp_import_dir}" &>/dev/null
  stop_spinner

  # Dọn dẹp thư mục tạm
  sudo rm -rf "${temp_extract_dir}"
  
  echo -e "\n${GREEN}[+] Chúc mừng! Quá trình phục hồi (Restore) TOÀN DIỆN đã thành công!${NC}"
  echo -e "${YELLOW}[*] N8N đã sẵn sàng với bộ dữ liệu Database, Workflows và Credentials cũ.${NC}"
  
  if [[ "$NON_INTERACTIVE" != "true" ]]; then
    echo ""
    read -n 1 -s -r -p "Nhấn phím bất kỳ để quay lại menu..."
  fi
}

# Chạy Backup tự động không cần prompt (Dành cho Cronjob)
run_auto_backup() {
  if [ ! -d "$N8N_DIR" ]; then exit 1; fi
  
  mkdir -p "$BACKUP_DIR"
  local timestamp=$(date +%Y%m%d_%H%M%S)
  local current_backup_dir="${BACKUP_DIR}/n8n_backup_${timestamp}"
  sudo mkdir -p "${current_backup_dir}"
  
  # 1. Export Credentials & Workflows
  local container_temp_export_dir="/home/node/.n8n/temp_export_$$"
  sudo docker exec -u node "${N8N_CONTAINER_NAME}" mkdir -p "${container_temp_export_dir}"
  sudo docker exec -u node "${N8N_CONTAINER_NAME}" n8n export:credentials --all --output="${container_temp_export_dir}/credentials.json" &>/dev/null || true
  sudo docker exec -u node "${N8N_CONTAINER_NAME}" n8n export:workflow --all --output="${container_temp_export_dir}/workflows.json" &>/dev/null || true
  sudo docker cp "${N8N_CONTAINER_NAME}:${container_temp_export_dir}/credentials.json" "${current_backup_dir}/credentials.json" &>/dev/null || true
  sudo docker cp "${N8N_CONTAINER_NAME}:${container_temp_export_dir}/workflows.json" "${current_backup_dir}/workflows.json" &>/dev/null || true
  sudo docker exec -u node "${N8N_CONTAINER_NAME}" rm -rf "${container_temp_export_dir}" &>/dev/null || true

  # 2. Database PostgreSQL
  local db_user=$(grep "^POSTGRES_USER=" "${ENV_FILE}" | cut -d'=' -f2)
  local db_name=$(grep "^POSTGRES_DB=" "${ENV_FILE}" | cut -d'=' -f2)
  if [[ -n "$db_user" && -n "$db_name" ]]; then
      sudo docker exec n8n_postgres pg_dump -U "$db_user" -d "$db_name" -F c -f "/tmp/database.dump" &>/dev/null || true
      sudo docker cp "n8n_postgres:/tmp/database.dump" "${current_backup_dir}/database.dump" &>/dev/null || true
      sudo docker exec n8n_postgres rm -f "/tmp/database.dump" &>/dev/null || true
  fi

  # 3. Config
  sudo cp "${N8N_DIR}/.env" "${current_backup_dir}/" &>/dev/null || true
  sudo cp "${N8N_DIR}/docker-compose.yml" "${current_backup_dir}/" &>/dev/null || true
  
  # 4. Gom lại thành file zip
  local backup_filename="n8n_full_backup_${timestamp}.tar.gz"
  local final_backup_file="${BACKUP_DIR}/${backup_filename}"
  cd ${BACKUP_DIR} && tar -czf ${final_backup_file} $(basename ${current_backup_dir}) 2>/dev/null
  sudo rm -rf "${current_backup_dir}"

  # 5. Xoá các bản backup cũ, chỉ giữ 7 bản gần nhất
  ls -1tr ${BACKUP_DIR}/n8n_full_backup_*.tar.gz 2>/dev/null | head -n -7 | xargs -r rm -f
}

# Cấu hình cài đặt Cronjob Backup
configure_auto_backup() {
  clear
  echo -e "${CYAN}=== CẤU HÌNH AUTO-BACKUP THEO LỊCH ===${NC}"
  echo -e "${YELLOW}Chức năng này sẽ tạo Cronjob tự động backup N8N vào lúc 0:00 mỗi ngày.${NC}"
  echo -e "${YELLOW}Chỉ giữ lại 7 bản backup gần nhất để tránh đầy ổ cứng.${NC}"
  echo ""
  
  # Kiểm tra xem đang bật hay tắt
  if crontab -l 2>/dev/null | grep -q "${INSTALL_PATH} --backup-cron"; then
      echo -e "Trạng thái hiện tại: ${GREEN}ĐANG BẬT (ON)${NC}"
  else
      echo -e "Trạng thái hiện tại: ${RED}ĐANG TẮT (OFF)${NC}"
  fi
  echo "--------------------------------------------------------"

  local confirm
  if [[ "$NON_INTERACTIVE" == "true" && -n "$CLI_VALUE" ]]; then
    confirm="$CLI_VALUE"
  else
    read -p "Bạn muốn ON (Bật) hay OFF (Tắt) chức năng này? (nhập on/off/hủy): " confirm
  fi

  if [[ "$confirm" == "on" || "$confirm" == "ON" ]]; then
    (crontab -l 2>/dev/null | grep -v "${INSTALL_PATH} --backup-cron") | crontab -
    (crontab -l 2>/dev/null; echo "0 0 * * * ${INSTALL_PATH} --backup-cron > /dev/null 2>&1") | crontab -
    echo -e "${GREEN}[+] Đã thiết lập Auto-Backup vào lúc 0:00 mỗi ngày thành công!${NC}"
  elif [[ "$confirm" == "off" || "$confirm" == "OFF" ]]; then
    (crontab -l 2>/dev/null | grep -v "${INSTALL_PATH} --backup-cron") | crontab -
    echo -e "${GREEN}[+] Đã TẮT Auto-Backup thành công!${NC}"
  else
    echo "Đã hủy thao tác."
  fi
  
  if [[ "$NON_INTERACTIVE" != "true" ]]; then
    sleep 2
  fi
}

# ---- src/lib/features/config.sh ----
# --- Cấu hình Môi trường (Environment Variables) ---

configure_environment() {
  while true; do
    clear
    echo -e "${CYAN}=== CẤU HÌNH BIẾN MÔI TRƯỜNG N8N ===${NC}"
    if [ ! -f "$ENV_FILE" ]; then
      echo -e "${RED}[!] Không tìm thấy cấu hình ${ENV_FILE}. Vui lòng cài đặt N8N trước.${NC}"
      if [[ "$NON_INTERACTIVE" != "true" ]]; then read -n 1 -s -r -p "Nhấn phím bất kỳ để quay lại menu..."; fi
      return 1
    fi

    if [[ "$NON_INTERACTIVE" == "true" && "$CLI_ACTION" == "config-set" ]]; then
      if [[ -z "$CLI_KEY" || -z "$CLI_VALUE" ]]; then
        echo -e "${RED}[!] Cần truyền đủ --key và --value để cài đặt. VD: n8n-host --config-set --key GENERIC_TIMEZONE --value Asia/Ho_Chi_Minh${NC}"
        return 1
      fi
      run_silent_command "Đang lưu cấu hình ${CLI_KEY}=${CLI_VALUE}" "update_env_file '${CLI_KEY}' '${CLI_VALUE}'" false
      echo -e "${GREEN}[+] Đã lưu cấu hình. Để áp dụng, hãy chạy: n8n-host --config-set --key RESTART --value NOW (hoặc Restart thủ công)${NC}"

      if [[ "$CLI_KEY" == "RESTART" ]]; then
         run_silent_command "Đang tải lại Server với Cấu hình Mới!" "cd ${N8N_DIR} && ${DOCKER_COMPOSE_CMD} up -d" false
         echo -e "${GREEN}[+] Hệ thống đã được Recreate với Cấu hình môi trường mới!${NC}"
      fi
      return 0
    fi

    # Lấy thông tin hiện tại
    local current_tz=$(grep "^GENERIC_TIMEZONE=" "${ENV_FILE}" | cut -d '=' -f2)
    local pkg_allow=$(grep "^NODE_FUNCTION_ALLOW_EXTERNAL=" "${ENV_FILE}" | cut -d '=' -f2)
    local pkg_builtin=$(grep "^NODE_FUNCTION_ALLOW_BUILTIN=" "${ENV_FILE}" | cut -d '=' -f2)
    local payload_size=$(grep "^N8N_PAYLOAD_SIZE_MAX=" "${ENV_FILE}" | cut -d '=' -f2)
    local execution_prune=$(grep "^EXECUTIONS_DATA_PRUNE=" "${ENV_FILE}" | cut -d '=' -f2)

    echo -e "${YELLOW}[*] Cấu hình đang áp dụng hiện tại:${NC}"
    echo "> [1] Múi giờ N8N:            ${current_tz:-'Không xác định'}"
    echo "> [2] Thư viện NPM Module:     External: ${pkg_allow:-'Mặc định'} | Built-in: ${pkg_builtin:-'Mặc định'}"
    echo "> [3] Giới hạn dung lượng tải: ${payload_size:-'Không xác định'} (Mặc định N8N: 16MB)"
    echo "> [4] Tự động xóa lịch sử:     ${execution_prune:-'false'} (Tắt là false)"
    echo "--------------------------------------------------------"
    echo " [5]  Cấu hình hệ thống Email (SMTP) cho N8N"
    echo " [6]  Khởi động lại (Restart) N8N để áp dụng cấu hình MỚI"
    echo " [0]  Quay lại Menu Chính"
    echo "--------------------------------------------------------"
    echo -e "${YELLOW}(Lưu ý: Bạn chọn các số từ 1-5 để thay đổi giá trị cấu hình tương ứng)${NC}\n"
    
    read -p "Chọn ID cấu hình bạn muốn thay đổi (0-6): " config_choice

    case "$config_choice" in
      1)
        echo ""
        read -p "Nhập Múi giờ muốn thay đổi (Vd: Asia/Ho_Chi_Minh, UTC, America/New_York): " new_tz
        if [ -n "$new_tz" ]; then
          run_silent_command "Cập nhật Timezone" "update_env_file 'GENERIC_TIMEZONE' '${new_tz}' && update_env_file 'TZ' '${new_tz}'" false
          echo -e "${GREEN}[+] Đã lưu cấu hình. Hãy nhớ khởi động lại N8N (chọn [5]).${NC}"
        fi
        sleep 1
        ;;
      2)
        echo ""
        echo -e "${YELLOW}Theo mặc định, Code Node không thể yêu cầu các thư viện Axios, Moment, Lodash... do bảo mật.${NC}"
        echo -e "${YELLOW}Lưu ý: Việc thêm * có thể tạo rủi ro nếu cho Hacker chạy lệnh.${NC}"
        read -p "Bạn muốn cho phép các thư viện bên ngoài không? (Để '*' là cho tất cả, hoặc 'axios,moment'): " new_ext
        read -p "Bạn muốn cho phép các thư viện built-in Node.js không? (VD: 'fs,crypto,*'): " new_blt
        if [ -n "$new_ext" ]; then run_silent_command "Thêm External NPM" "update_env_file 'NODE_FUNCTION_ALLOW_EXTERNAL' '${new_ext}'" false; fi
        if [ -n "$new_blt" ]; then run_silent_command "Thêm Built-in NPM" "update_env_file 'NODE_FUNCTION_ALLOW_BUILTIN' '${new_blt}'" false; fi
        echo -e "${GREEN}[+] Đã lưu cấu hình. Hãy nhớ khởi động lại N8N (chọn [5]).${NC}"
        sleep 1
        ;;
      3)
        echo ""
        echo -e "${YELLOW}Nếu bạn cần import file json to, tải file lớn qua webhook, hay memory giới hạn, bạn cần đổi cỡ MB này.${NC}"
        read -p "Nhập giới hạn lưu lượng (Vd: 50, 256, 1024) [Tính theo MB]: " new_size
        if [ -n "$new_size" ] && [[ "$new_size" =~ ^[0-9]+$ ]]; then
          run_silent_command "Tăng Payload Max Size" "update_env_file 'N8N_PAYLOAD_SIZE_MAX' '${new_size}'" false
          echo -e "${GREEN}[+] Đã lưu cấu hình N8N_PAYLOAD_SIZE_MAX thành ${new_size}. Nhưng cần kiểm tra Nginx Reverse Proxy xem giới hạn có quá thấp không!${NC}"
        fi
        sleep 2
        ;;
      4)
        echo ""
        echo -e "${YELLOW}Tự xóa dữ liệu (Execution History) giúp nhẹ CSDL.${NC}"
        read -p "Bật tự động xóa History? (true/false): " p_enable
        if [[ "$p_enable" == "true" ]]; then
           read -p "Giữ lại lịch sử History thành công tối đa (VD: 336 giờ = 14 ngày): " max_age
           if [[ -z "$max_age" ]]; then max_age=336; fi
           run_silent_command "Sửa prune" "update_env_file 'EXECUTIONS_DATA_PRUNE' 'true' && update_env_file 'EXECUTIONS_DATA_MAX_AGE' '${max_age}'" false
        elif [[ "$p_enable" == "false" ]]; then
           run_silent_command "Sửa prune" "update_env_file 'EXECUTIONS_DATA_PRUNE' 'false'" false
        fi
        echo -e "${GREEN}[+] Đã lưu cấu hình. Hãy nhớ khởi động lại N8N (chọn [5]).${NC}"
        sleep 1
        ;;
      5)
        echo ""
        echo -e "${CYAN}--- CẤU HÌNH GỬI EMAIL SMTP ---${NC}"
        echo -e "${YELLOW}Tính năng này giúp N8N có thể gửi email mời user, báo lỗi hoặc dùng cho node Email Send.${NC}"
        read -p "Nhập SMTP Host (Vd: smtp.gmail.com): " smtp_host
        read -p "Nhập SMTP Port (Vd: 465 hoặc 587): " smtp_port
        read -p "Nhập SMTP User (Email đăng nhập): " smtp_user
        read -s -p "Nhập SMTP Password (Mật khẩu ứng dụng): " smtp_pass
        echo ""
        read -p "Nhập Tên người gửi (Sender/From Email, có thể là email đăng nhập): " smtp_sender
        
        if [[ -n "$smtp_host" && -n "$smtp_user" && -n "$smtp_pass" ]]; then
          run_silent_command "Cập nhật cấu hình SMTP vào N8N" "\
          update_env_file 'N8N_EMAIL_MODE' 'smtp' && \
          update_env_file 'N8N_SMTP_HOST' '${smtp_host}' && \
          update_env_file 'N8N_SMTP_PORT' '${smtp_port:-465}' && \
          update_env_file 'N8N_SMTP_USER' '${smtp_user}' && \
          update_env_file 'N8N_SMTP_PASS' '${smtp_pass}' && \
          update_env_file 'N8N_SMTP_SENDER' '${smtp_sender:-${smtp_user}}'" false
          echo -e "${GREEN}[+] Đã lưu cấu hình. Hãy nhớ khởi động lại N8N (chọn [6]).${NC}"
        else
          echo -e "${RED}[!] Bỏ qua do thiếu thông tin (Host, User hoặc Pass).${NC}"
        fi
        sleep 2
        ;;
      6)
        echo ""
        run_silent_command "Đang tải lại Server với Cấu hình Mới!" "cd ${N8N_DIR} && ${DOCKER_COMPOSE_CMD} up -d" false
        echo -e "${GREEN}[+] Hệ thống đã được Recreate với Cấu hình môi trường mới!${NC}"
        sleep 2
        ;;
      0)
        return 0
        ;;
      *)
        echo -e "${RED}[!] Lựa chọn không hợp lệ.${NC}"
        sleep 1
        ;;
    esac
  done
}

# ---- src/lib/features/audit.sh ----
# --- System & Security Audit ---

system_audit() {
  local is_json="false"
  if [[ "$NON_INTERACTIVE" == "true" && "$CLI_ACTION" == "audit-json" ]]; then
    is_json="true"
  fi

  if [[ "$is_json" == "false" ]]; then
    clear
    echo -e "${CYAN}=== SYSTEM & SECURITY AUDIT ===${NC}"
    echo -e "${YELLOW}[*] Đang tiến hành quét lỗ hổng và kiểm tra tài nguyên hệ thống...${NC}\n"
  fi

  local issue_count=0

  # 1. Kiểm tra Permission file .env
  local env_status="unknown"
  if [[ "$is_json" == "false" ]]; then
    echo -n -e "1. Kiểm tra cấu hình bảo mật (.env): "
  fi
  if [ -f "${ENV_FILE}" ]; then
    local env_perms
    env_perms=$(stat -c "%a" "${ENV_FILE}")
    if [[ "$env_perms" == "777" || "$env_perms" == "666" || "$env_perms" == "644" ]]; then
      if [[ "$is_json" == "false" ]]; then
        echo -e "${RED}CẢNH BÁO [Mức độ: Cao]${NC}"
        echo -e "   -> File ${ENV_FILE} đang có quyền ${env_perms} (không an toàn)."
        echo -e "   -> Đang tự động sửa lỗi (chmod 600)..."
      fi
      sudo chmod 600 "${ENV_FILE}"
      if [[ "$is_json" == "false" ]]; then
        echo -e "   ${GREEN}[+] Đã fix quyền file .env thành 600.${NC}"
      fi
      env_status="fixed_to_600"
      issue_count=$((issue_count+1))
    else
      if [[ "$is_json" == "false" ]]; then echo -e "${GREEN}An toàn (${env_perms})${NC}"; fi
      env_status="safe_${env_perms}"
    fi
  else
    if [[ "$is_json" == "false" ]]; then echo -e "${YELLOW}Bỏ qua (Chưa cài đặt N8N)${NC}"; fi
    env_status="not_installed"
  fi

  # 2. Kiểm tra Dung lượng ổ cứng (Disk Space)
  if [[ "$is_json" == "false" ]]; then echo -n -e "2. Kiểm tra dung lượng ổ đĩa phân vùng gốc (/): "; fi
  local disk_usage
  disk_usage=$(df -h / | awk 'NR==2 {print $5}' | sed 's/%//' | tr -dc '0-9')
  # Đảm bảo rỗng thì = 0
  if [[ -z "$disk_usage" ]]; then disk_usage=0; fi
  local disk_status="ok"
  if [ "$disk_usage" -ge 80 ]; then
    if [[ "$is_json" == "false" ]]; then
      echo -e "${RED}CẢNH BÁO [Mức độ: Cao]${NC}"
      echo -e "   -> Ổ đĩa đã sử dụng ${disk_usage}%. Nếu đạt 100%, Database PostgreSQL sẽ Crash!"
      echo -e "   -> Vui lòng dùng tính năng [16] Dọn rác máy chủ hoặc xóa bớt file thừa."
    fi
    disk_status="warning_high"
    issue_count=$((issue_count+1))
  else
    if [[ "$is_json" == "false" ]]; then echo -e "${GREEN}Tốt (${disk_usage}%)${NC}"; fi
  fi

  # 3. Kiểm tra Thời hạn SSL
  local ssl_status="unknown"
  local ssl_days_left="-1"
  if [[ "$is_json" == "false" ]]; then echo -n -e "3. Kiểm tra chứng chỉ SSL/HTTPS: "; fi
  if [ -f "${ENV_FILE}" ]; then
    local domain_name
    domain_name=$(grep "^DOMAIN_NAME=" "${ENV_FILE}" | cut -d'=' -f2)
    if [[ -n "$domain_name" ]]; then
      local expiry_date
      expiry_date=$(echo | openssl s_client -servername "${domain_name}" -connect "${domain_name}:443" 2>/dev/null | openssl x509 -noout -enddate 2>/dev/null | cut -d= -f2)
      if [[ -n "$expiry_date" ]]; then
        # Chuyển đổi định dạng thời gian để tính toán
        local expiry_epoch=$(date -d "${expiry_date}" +%s 2>/dev/null || date -D "%b %d %H:%M:%S %Y %Z" -d "${expiry_date}" +%s 2>/dev/null)
        local current_epoch=$(date +%s)
        if [[ -n "$expiry_epoch" ]]; then
          local days_left=$(( (expiry_epoch - current_epoch) / 86400 ))
          ssl_days_left=$days_left
          if [ "$days_left" -lt 15 ]; then
             if [[ "$is_json" == "false" ]]; then
               echo -e "${RED}CẢNH BÁO [Mức độ: Thấp]${NC}"
               echo -e "   -> SSL cho ${domain_name} sẽ hết hạn trong ${days_left} ngày tới (${expiry_date})."
               echo -e "   -> Vui lòng gia hạn Let's Encrypt hoặc Cloudflare."
             fi
             ssl_status="warning_expiring"
             issue_count=$((issue_count+1))
          else
             if [[ "$is_json" == "false" ]]; then echo -e "${GREEN}An toàn (Cấp cho ${domain_name}, còn ${days_left} ngày)${NC}"; fi
             ssl_status="safe"
          fi
        else
          if [[ "$is_json" == "false" ]]; then echo -e "${YELLOW}Không thể tính toán (${expiry_date})${NC}"; fi
          ssl_status="error_parsing_date"
        fi
      else
        if [[ "$is_json" == "false" ]]; then echo -e "${YELLOW}Không lấy được (Trang web có bật HTTPS không?)${NC}"; fi
        ssl_status="error_fetching"
      fi
    else
      if [[ "$is_json" == "false" ]]; then echo -e "${YELLOW}Bỏ qua (Chưa có tên miền)${NC}"; fi
      ssl_status="no_domain"
    fi
  else
    if [[ "$is_json" == "false" ]]; then echo -e "${YELLOW}Bỏ qua (Chưa cài đặt N8N)${NC}"; fi
    ssl_status="not_installed"
  fi

  if [[ "$is_json" == "true" ]]; then
    # In ra dạng JSON cơ bản thông qua jq nếu có, hoặc dùng echo
    echo "{"
    echo "  \"issueCount\": ${issue_count},"
    echo "  \"envFileStatus\": \"${env_status}\","
    echo "  \"diskUsagePercent\": ${disk_usage},"
    echo "  \"diskStatus\": \"${disk_status}\","
    echo "  \"sslStatus\": \"${ssl_status}\","
    echo "  \"sslDaysLeft\": ${ssl_days_left}"
    echo "}"
    return 0
  fi

  echo -e "\n--------------------------------------------------------"
  if [ $issue_count -eq 0 ]; then
    echo -e "${GREEN}[+] Hệ thống hiện tại AN TOÀN và TUYỆT VỜI. Bạn không cần lo lắng gì cả!${NC}"
  else
    echo -e "${YELLOW}[!] Phát hiện ${issue_count} rủi ro. Vui lòng kiểm tra lại theo hướng dẫn bên trên.${NC}"
  fi
  
  if [[ "$NON_INTERACTIVE" != "true" ]]; then
    echo ""
    read -n 1 -s -r -p "Nhấn phím bất kỳ để quay lại menu..."
  fi
}

# ---- src/lib/features/self_update.sh ----
# --- Tự động cập nhật Script ---

update_script() {
  clear
  echo -e "${CYAN}=== CẬP NHẬT N8N CLOUD MANAGER ===${NC}"
  echo -e "${YELLOW}[*] Hệ thống sẽ tải phiên bản script (n8n-host) mới nhất từ kho lưu trữ của NCHQ02...${NC}"
  read -p "Bạn có muốn tiếp tục cập nhật không? (y/n): " confirm
  if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then
    echo "Đã hủy thao tác."
    sleep 1
    return 0
  fi

  # URL thô (raw.githubusercontent.com) của file dist/n8n-host.sh (Sẽ tải trực tiếp script đã build)
  # Có thể tùy chỉnh link repo tại đây
  local UPDATE_URL="https://raw.githubusercontent.com/NCHQ02/n8n-script-2026/main/dist/n8n-host.sh"
  local TEMP_FILE="/tmp/n8n-host-update.sh"

  echo -e "\nĐang tải xuống phiên bản mới nhất..."
  if curl -sSL --fail "$UPDATE_URL" -o "$TEMP_FILE"; then
    echo -e "${GREEN}[+] Tải thành công. Đang ghi đè file hiện tại...${NC}"
    sudo mv "$TEMP_FILE" "$INSTALL_PATH"
    sudo chmod +x "$INSTALL_PATH"
    echo -e "${GREEN}[+] Đã Cập nhật xong N8N Cloud Manager.${NC}"
    echo -e "${YELLOW}Vui lòng chạy lại lệnh 'n8n-host' để trải nghiệm phiên bản mới nhất!${NC}\n"
    exit 0
  else
    echo -e "${RED}[!] Không thể tải phiên bản mới. Kiểm tra kết nối Internet hoặc link Repo Repository Github.${NC}"
    sudo rm -f "$TEMP_FILE"
    echo ""
    read -n 1 -s -r -p "Nhấn phím bất kỳ để quay lại menu..."
  fi
}

# ---- src/lib/features/marketplace.sh ----
# --- Marketplace (Chợ Templates N8N) ---

open_marketplace() {
  while true; do
    clear
    echo -e "${CYAN}=== KHÁM PHÁ & CÀI ĐẶT WORKFLOW TỰ ĐỘNG (MARKETPLACE) ===${NC}"
    echo -e "${YELLOW}Chào mừng đến với chợ Template của NCHQ02!${NC}"
    echo -e "${GREEN}Hệ thống sẽ tải danh sách các Workflow có sẵn từ kho lưu trữ GitHub và tự động cài đặt vào N8N của bạn.${NC}"
    echo "--------------------------------------------------------"
    
    # Định nghĩa danh sách các mẫu (id|tên|link json)
    # Tương lai có thể cào tự động bằng API Github, nhưng fix cứng mảng sẽ an toàn và nhanh hơn cho Bash Script
    local templates=(
      "1|Luồng import workflow credential|import-workflow-credential.json"
    )

    local choice
    if [[ "$NON_INTERACTIVE" == "true" && -n "$CLI_ID" ]]; then
      choice="$CLI_ID"
    else
      # Hiển thị Menu
      for item in "${templates[@]}"; do
        local id=$(echo "$item" | cut -d'|' -f1)
        local name=$(echo "$item" | cut -d'|' -f2)
        printf " [%-2s] %s\n" "$id" "$name"
      done

      echo "--------------------------------------------------------"
      echo " [0]  Quay lại Menu Chính"
      echo ""
      
      read -p "Chọn Workflow bạn muốn cài đặt (0-${#templates[@]}): " choice
      
      if [ "$choice" -eq 0 ] 2>/dev/null; then
        return 0
      fi
    fi
    
    # Tìm kiếm choice trong danh sách
    local selected_name=""
    local selected_file=""
    
    for item in "${templates[@]}"; do
      local id=$(echo "$item" | cut -d'|' -f1)
      if [ "$id" == "$choice" ]; then
        selected_name=$(echo "$item" | cut -d'|' -f2)
        selected_file=$(echo "$item" | cut -d'|' -f3)
        break
      fi
    done
    
    if [[ -z "$selected_name" ]]; then
      echo -e "${RED}[!] Lựa chọn không hợp lệ (ID: $choice).${NC}"
      if [[ "$NON_INTERACTIVE" == "true" ]]; then return 1; fi
      sleep 1
      continue
    fi
    
    echo -e "\n${YELLOW}[*] Bạn đã chọn: ${CYAN}${selected_name}${NC}"
    
    if [[ "$NON_INTERACTIVE" != "true" ]]; then
      read -p "Phiên bản này sẽ được tải xuống và Import trực tiếp vào N8N. Tiếp tục? (y/n): " confirm
      if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then
        echo "Đã hủy."
        sleep 1
        continue
      fi
    fi
    
    local BASE_URL="https://raw.githubusercontent.com/NCHQ02/n8n-script-2026/main/templates"
    local TARGET_URL="${BASE_URL}/${selected_file}"
    local TEMP_JSON="/tmp/n8n_marketplace_template_$$.json"
    
    start_spinner "Đang tải dữ liệu mẫu từ GitHub..."
    if curl -sSL --fail "$TARGET_URL" -o "$TEMP_JSON"; then
      stop_spinner
      echo -e "${GREEN}[+] Tải thành công file cấu hình!${NC}"
      
      start_spinner "Đang cài đặt Workflow vào N8N..."
      local container_temp_import_dir="/home/node/.n8n/temp_marketplace_$$"
      
      # Tạo folder tạm trong container
      sudo docker exec -u node "${N8N_CONTAINER_NAME}" mkdir -p "${container_temp_import_dir}"
      
      # Copy file json vào container
      sudo docker cp "${TEMP_JSON}" "${N8N_CONTAINER_NAME}:${container_temp_import_dir}/template.json"
      
      # Import workflow
      local import_result
      import_result=$(sudo docker exec -u node "${N8N_CONTAINER_NAME}" n8n import:workflow --input="${container_temp_import_dir}/template.json" 2>&1)
      local import_exit_code=$?
      
      # Xoá folder tạm
      sudo docker exec -u node "${N8N_CONTAINER_NAME}" rm -rf "${container_temp_import_dir}"
      sudo rm -f "$TEMP_JSON"
      
      stop_spinner
      
      if [ $import_exit_code -eq 0 ]; then
        echo -e "${GREEN}[+] Khởi tạo thành công! Workflow đã được đưa vào Database của N8N.${NC}"
        echo -e "${YELLOW}Lưu ý: Bạn hãy đăng nhập vào N8N để cấu hình Credentials (Api key, Token) cho luồng chạy nhé!${NC}"
      else
        echo -e "${RED}[!] Cài đặt thất bại! Chi tiết lỗi:${NC}"
        echo "$import_result"
      fi
    else
      stop_spinner
      echo -e "${RED}[!] Lỗi: Không thể tải file ${selected_file} từ GitHub.${NC}"
      echo -e "${YELLOW}File mẫu này có thể chưa được tác giả NCHQ02 upload lên kho chứa.${NC}"
      sudo rm -f "$TEMP_JSON"
    fi
    
    if [[ "$NON_INTERACTIVE" == "true" ]]; then
      return 0
    else
      echo ""
      read -n 1 -s -r -p "Nhấn phím bất kỳ để quay lại MarketPlace..."
    fi
  done
}

# ---- src/main.sh ----
uninstall() {
    echo -e "\n${YELLOW}[*] Đang kiểm tra và gỡ bỏ công cụ tại: ${INSTALL_PATH}${NC}"
    if [[ -f "$INSTALL_PATH" ]]; then
        if sudo rm -f "$INSTALL_PATH"; then
            echo -e "${GREEN}[+] Đã gỡ bỏ '$INSTALL_PATH' thành công.${NC}"
        else
            echo -e "${RED}[!] Lỗi khi thực hiện lệnh gỡ bỏ (kiểm tra quyền sudo).${NC}"
        fi
    else
        echo -e "${YELLOW}[!] Không tìm thấy file công cụ tại '${INSTALL_PATH}'.${NC}"
    fi
    exit 0
}

show_help() {
    echo "  --help              Hiển thị thông tin trợ giúp này"
    echo "  --install           Cài đặt N8N không cần tương tác (kết hợp --domain, --email)"
    echo "  --domain <str>      Truyền tên miền ứng dụng"
    echo "  --email <str>       Truyền email để đăng ký SSL HOẶC user N8N"
    echo "  --backup            Chạy Siêu Backup toàn hệ thống"
    echo "  --backup-cron       Chạy Backup dạng Cronjob (giữ lại 7 file)"
    echo "  --prune-cache       Chạy Dọn rác máy chủ (Docker Prune)"
    echo "  --disable-2fa       Tắt MFA cho một user (kết hợp --email)"
    echo "  --reset-owner       Reset tài khoản Owner N8N"
    echo "  --export            Export dữ liệu workflow/credentials (kết hợp --path)"
    echo "  --import            Import dữ liệu workflow/credentials (kết hợp --file)"
    echo "  --restore           Phục hồi toàn bộ server từ file nén (kết hợp --file)"
    echo "  --install-template  Cài template mẫu từ Marketplace (kết hợp --id)"
    echo "  --audit-json        Quét hệ thống và xuất kết quả ra định dạng JSON"
    echo "  --config-set        Set cấu hình môi trường .env (kết hợp --key, --value)"
    echo "  --path <str>        Truyền đường dẫn thư mục"
    echo "  --file <str>        Truyền đường dẫn tập tin"
    echo "  --id <str>          Truyền ID (cho Marketplace)"
    echo "  --key <str>         Truyền tên biến môi trường (Ví dụ: GENERIC_TIMEZONE)"
    echo "  --value <str>       Truyền giá trị biến môi trường (Ví dụ: Asia/Ho_Chi_Minh)"
    echo "  --uninstall         Gỡ bỏ n8n-host khỏi hệ thống"
    exit 0
}

if [[ "$1" == "--help" ]]; then
    show_help
fi

export NON_INTERACTIVE="false"
export CLI_DOMAIN=""
export CLI_EMAIL=""
export CLI_PATH=""
export CLI_FILE=""
export CLI_ID=""
export CLI_KEY=""
export CLI_VALUE=""
CLI_ACTION=""

while [[ $# -gt 0 ]]; do
  case "$1" in
    --install) CLI_ACTION="install"; shift ;;
    --domain) shift; export CLI_DOMAIN="$1"; shift ;;
    --email) shift; export CLI_EMAIL="$1"; shift ;;
    --path) shift; export CLI_PATH="$1"; shift ;;
    --file) shift; export CLI_FILE="$1"; shift ;;
    --id) shift; export CLI_ID="$1"; shift ;;
    --key) shift; export CLI_KEY="$1"; shift ;;
    --value) shift; export CLI_VALUE="$1"; shift ;;
    --backup) CLI_ACTION="backup"; shift ;;
    --prune-cache) CLI_ACTION="prune-cache"; shift ;;
    --disable-2fa) CLI_ACTION="disable-2fa"; shift ;;
    --reset-owner) CLI_ACTION="reset-owner"; shift ;;
    --export) CLI_ACTION="export"; shift ;;
    --import) CLI_ACTION="import"; shift ;;
    --restore) CLI_ACTION="restore"; shift ;;
    --install-template) CLI_ACTION="install-template"; shift ;;
    --audit-json) CLI_ACTION="audit-json"; shift ;;
    --config-set) CLI_ACTION="config-set"; shift ;;
    --uninstall) uninstall; exit 0 ;;
    --help) show_help ;;
    --backup-cron) run_auto_backup; exit 0 ;;
    *) echo -e "${RED}[!] Tuỳ chọn không hợp lệ: $1${NC}"; show_help ;;
  esac
done

if [[ -n "$CLI_ACTION" ]]; then
  export NON_INTERACTIVE="true"
  case "$CLI_ACTION" in
    install) install ;;
    backup) run_auto_backup; echo -e "${GREEN}[+] Đã chạy xong Backup qua CLI!${NC}" ;;
    prune-cache) docker_prune ;;
    disable-2fa) disable_mfa ;;
    reset-owner) reset_user_login ;;
    export) export_all_data ;;
    import) import_data ;;
    restore) restore_server ;;
    install-template) open_marketplace ;;
    audit-json) system_audit ;;
    config-set) configure_environment ;;
  esac
  exit 0
fi


